source:
'use client'
/**
 * src/app/(dashboard)/calls/page.tsx
 *
 * Full Calls tab redesigned based on CallCenter Pro mockups.
 * 3-Column Layout:
 * 1. Left: Active Contacts Sidebar
 * 2. Middle: Today's Overview (Global) OR Contact Interaction History (Active)
 * 3. Right: Empty State OR Contact Profile details (Tags, Health)
 */

import { useEffect, useCallback, useState, useRef } from 'react'
import { useSearchParams } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { useWhatsAppCall } from '@/hooks/useWhatsAppCall'
import type { Conversation } from '@/types'

/* ── Types ────────────────────────────────────────────────────────────────── */
interface CallLog {
  id:           string
  body:         string | null
  direction:    string
  created_at:   string
  content_type: string | null
  meta:         Record<string, any>
}
interface Recording {
  id:               string
  duration_seconds: number | null
  mime_type:        string
  created_at:       string
  call_id:          string | null
  storage_path:     string
}
interface Summary {
  total_calls:          number
  outbound_calls:       number
  inbound_calls:        number
  missed_calls:         number
  total_duration_seconds: number
  avg_duration_seconds:   number
  last_call_at:         string | null
}

/* ── Helpers ──────────────────────────────────────────────────────────────── */
function fmtDur(s: number | null | undefined) {
  if (!s) return '—'
  const m = Math.floor(s / 60), sec = s % 60
  return m > 0 ? `${m}m ${sec}s` : `${sec}s`
}
function fmtTime(iso: string) {
  return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
}
function fmtDate(iso: string) {
  const diff = Math.floor((Date.now() - new Date(iso).getTime()) / 86400000)
  if (diff === 0) return 'Today'
  if (diff === 1) return 'Yesterday'
  if (diff < 7)  return `${diff}d ago`
  return new Date(iso).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })
}

const STATE_LABEL: Record<string, string> = {
  idle:                  'Ready',
  checking:              'Checking…',
  permission_required:   'Permission required',
  requesting_permission: 'Sending request…',
  connecting:            'Connecting…',
  ringing:               'Ringing…',
  connected:             'Connected',
  ending:                'Ending…',
  error:                 'Call failed',
}

function logIcon(event: string, dir: string) {
  const e = (event ?? '').toLowerCase()
  if (['missed', 'no_answer', 'busy'].includes(e)) return { icon: 'fa-solid fa-phone-missed', color: '#ef4444', label: 'Missed', bg: 'rgba(239,68,68,0.1)' }
  if (['failed', 'rejected'].includes(e))          return { icon: 'fa-solid fa-phone-slash',  color: '#f97316', label: 'Failed', bg: 'rgba(249,115,22,0.1)' }
  if (dir === 'inbound')                           return { icon: 'fa-solid fa-phone-arrow-down-left', color: '#10b981', label: 'Incoming', bg: 'rgba(16,185,129,0.1)' }
  return                                                  { icon: 'fa-solid fa-phone-arrow-up-right',  color: '#3b82f6', label: 'Outgoing', bg: 'rgba(59,130,246,0.1)' }
}

/* ── Component ────────────────────────────────────────────────────────────── */
export default function CallsPage() {
  const supabase     = createClient()
  const searchParams = useSearchParams()

  const [workspaceId,   setWorkspaceId]   = useState<string | null>(null)
  const [conversations, setConversations] = useState<Conversation[]>([])
  const [activeId,      setActiveId]      = useState<string | null>(null)
  const [callLogs,      setCallLogs]      = useState<CallLog[]>([])
  const [globalLogs,    setGlobalLogs]    = useState<CallLog[]>([])
  const [recordings,    setRecordings]    = useState<Recording[]>([])
  const [summary,       setSummary]       = useState<Summary | null>(null)
  const [globalSummary, setGlobalSummary] = useState<Summary | null>(null)
  const [loading,       setLoading]       = useState(false)
  const [search,        setSearch]        = useState('')
  const [tab,           setTab]           = useState<'all' | 'online' | 'vip'>('all')
  const [playingId,     setPlayingId]     = useState<string | null>(null)
  const [playingUrl,    setPlayingUrl]    = useState<string | null>(null)
  const [noteText,      setNoteText]      = useState('')
  const [noteLoading,   setNoteLoading]   = useState(false)
  const audioRef = useRef<HTMLAudioElement | null>(null)

  /* Recording upload callback — refresh recordings list */
  const onRecordingUploaded = useCallback(() => {
    if (activeId) loadCallData(activeId)
  }, [activeId])

  const call = useWhatsAppCall(activeId, onRecordingUploaded)

  /* ── Load WA conversations & global data ────────────────────────────────── */
  const loadConversations = useCallback(async () => {
    const { data: { session } } = await supabase.auth.getSession()
    if (!session) return
    const { data: profile } = await supabase.from('profiles').select('workspace_id').eq('id', session.user.id).single()
    if (!profile) return
    setWorkspaceId(profile.workspace_id)

    const { data } = await supabase
      .from('conversations')
      .select(`id, platform, status, last_message, last_message_at, unread_count,
               contact:contacts(id, name, phone, avatar_url, tags),
               channel:channels(id, name, platform, external_id)`)
      .eq('workspace_id', profile.workspace_id)
      .eq('platform', 'whatsapp')
      .order('last_message_at', { ascending: false })
      .limit(100)

    setConversations((data ?? []) as any)

    // Fetch Global Summary
    const sumRes = await supabase.from('call_summary').select('*').eq('workspace_id', profile.workspace_id).is('conversation_id', null).maybeSingle()
    if (sumRes.data) setGlobalSummary(sumRes.data as Summary)

    // Fetch Global Activity
    const logsRes = await supabase.from('messages').select('id,body,direction,created_at,meta,conversation:conversations(contact:contacts(name,phone))')
      .eq('workspace_id', profile.workspace_id).eq('content_type', 'call')
      .order('created_at', { ascending: false }).limit(20)
    setGlobalLogs((logsRes.data ?? []) as any)
  }, [])

  useEffect(() => { loadConversations() }, [loadConversations])

  /* ── Auto-select from ?cid= ─────────────────────────────────────────────── */
  useEffect(() => {
    const cid = searchParams.get('cid')
    if (cid) setActiveId(cid)
  }, [searchParams])

  /* ── When active conversation changes ───────────────────────────────────── */
  useEffect(() => {
    if (!activeId) return
    call.reset()
    call.checkPermission()
    loadCallData(activeId)
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeId])

  /* ── Load logs, recordings, summary ─────────────────────────────────────── */
  async function loadCallData(convId: string) {
    setLoading(true)
    const [logsRes, recsRes, sumRes] = await Promise.all([
      supabase.from('messages').select('id,body,direction,created_at,meta,content_type')
        .eq('conversation_id', convId).in('content_type', ['call', 'text']) // fetch notes too
        .order('created_at', { ascending: false }).limit(50),
      supabase.from('call_recordings').select('id,duration_seconds,mime_type,created_at,call_id,storage_path')
        .eq('conversation_id', convId).order('created_at', { ascending: false }).limit(20),
      supabase.from('call_summary').select('*').eq('conversation_id', convId).maybeSingle(),
    ])
    setCallLogs((logsRes.data ?? []) as CallLog[])
    setRecordings((recsRes.data ?? []) as Recording[])
    setSummary(sumRes.data as Summary ?? null)
    setLoading(false)
  }

  /* ── Playback ────────────────────────────────────────────────────────────── */
  async function playRecording(rec: Recording) {
    if (playingId === rec.id) {
      audioRef.current?.pause()
      setPlayingId(null)
      setPlayingUrl(null)
      return
    }
    const res  = await fetch(`/api/whatsapp/call-recording?id=${rec.id}`)
    const data = await res.json()
    if (!data.ok || !data.signed_url) { alert('Could not load recording'); return }
    setPlayingId(rec.id)
    setPlayingUrl(data.signed_url)
    setTimeout(() => audioRef.current?.play(), 100)
  }

  /* ── Quick Note ──────────────────────────────────────────────────────────── */
  async function submitNote() {
    if (!noteText.trim() || !activeId || !workspaceId) return
    setNoteLoading(true)
    const { error } = await supabase.from('messages').insert({
      conversation_id: activeId,
      workspace_id:    workspaceId,
      direction:       'outbound',
      content_type:    'text',
      body:            noteText.trim(),
      status:          'delivered',
      is_note:         true,
      meta:            { note_type: 'quick_note' }
    })
    setNoteLoading(false)
    if (!error) {
      setNoteText('')
      loadCallData(activeId)
    }
  }

  /* ── Derived ─────────────────────────────────────────────────────────────── */
  const activeConv = conversations.find(c => c.id === activeId) ?? null
  const contact    = activeConv?.contact as any
  const name       = contact?.name || contact?.phone || 'Unknown'
  const tags       = contact?.tags || []

  const filtered = conversations.filter(c => {
    const ct = c.contact as any
    const q = search.toLowerCase()
    const matchesSearch = !q || ct?.name?.toLowerCase().includes(q) || ct?.phone?.includes(q)
    if (!matchesSearch) return false
    if (tab === 'vip') return ct?.tags?.includes('VIP')
    // online is mock for now
    if (tab === 'online') return Math.random() > 0.5 
    return true
  })

  /* ── Render ──────────────────────────────────────────────────────────────── */
  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden', background: '#f8fafc', color: '#0f172a', fontFamily: '"Inter", sans-serif' }}>
      {/* Global CSS overrides for clean scrollbars */}
      <style>{`
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        input:focus { outline: none; border-color: #3b82f6 !important; box-shadow: 0 0 0 3px rgba(59,130,246,0.1) !important; }
        textarea:focus { outline: none; border-color: #3b82f6 !important; box-shadow: 0 0 0 3px rgba(59,130,246,0.1) !important; }
      `}</style>

      {/* Hidden audio element */}
      <audio ref={audioRef} src={playingUrl ?? undefined} onEnded={() => { setPlayingId(null); setPlayingUrl(null) }} />

      {/* ══ COLUMN 1: Active Contacts Sidebar ════════════════════════════════════ */}
      <div style={{ width: 320, minWidth: 320, borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', background: '#fff', zIndex: 10 }}>

        {/* Header & Search */}
        <div style={{ padding: '24px 20px 16px' }}>
          <h2 style={{ fontSize: 18, fontWeight: 700, margin: '0 0 16px 0', color: '#0f172a' }}>Active Contacts</h2>
          <div style={{ position: 'relative' }}>
            <i className="fa-solid fa-search" style={{ position: 'absolute', left: 14, top: 12, color: '#94a3b8', fontSize: 14 }} />
            <input
              placeholder="Search contacts..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              style={{ width: '100%', padding: '10px 14px 10px 38px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, background: '#f8fafc', transition: 'all 0.2s' }}
            />
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display: 'flex', padding: '0 20px 12px', borderBottom: '1px solid #e2e8f0', gap: 16 }}>
          {(['all', 'online', 'vip'] as const).map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              background: 'none', border: 'none', cursor: 'pointer', padding: '4px 0',
              fontSize: 13, fontWeight: tab === t ? 600 : 500, textTransform: 'capitalize',
              color: tab === t ? '#3b82f6' : '#64748b',
              borderBottom: tab === t ? '2px solid #3b82f6' : '2px solid transparent',
              transition: 'all 0.2s'
            }}>
              {t}
            </button>
          ))}
        </div>

        {/* Contact List */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '12px 12px' }}>
          {filtered.length === 0 && <div style={{ textAlign: 'center', padding: '32px 20px', color: '#94a3b8', fontSize: 14 }}>No contacts found</div>}
          {filtered.map(conv => {
            const ct    = conv.contact as any
            const cname = ct?.name || ct?.phone || 'Unknown'
            const isAct = conv.id === activeId
            const lmsg  = conv.last_message as any
            const msgSnippet = typeof lmsg === 'string' ? lmsg : lmsg?.body ?? 'Interaction…'

            return (
              <div key={conv.id} onClick={() => setActiveId(conv.id)} style={{
                display: 'flex', alignItems: 'center', gap: 12, padding: '12px', cursor: 'pointer',
                borderRadius: 8, background: isAct ? '#eff6ff' : 'transparent',
                transition: 'background 0.2s', marginBottom: 4
              }}>
                <div style={{ position: 'relative' }}>
                  <div style={{ width: 42, height: 42, borderRadius: '50%', background: isAct ? '#3b82f6' : '#e2e8f0', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16, fontWeight: 600, color: isAct ? '#fff' : '#64748b' }}>
                    {cname.charAt(0).toUpperCase()}
                  </div>
                  {/* Mock Online dot */}
                  <div style={{ position: 'absolute', bottom: 0, right: 0, width: 12, height: 12, borderRadius: '50%', background: '#10b981', border: '2px solid #fff' }} />
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                    <div style={{ fontSize: 14, fontWeight: 600, color: isAct ? '#1e40af' : '#0f172a', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{cname}</div>
                    <div style={{ fontSize: 11, color: '#94a3b8', flexShrink: 0 }}>{fmtTime(conv.last_message_at)}</div>
                  </div>
                  <div style={{ fontSize: 13, color: '#64748b', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                    {msgSnippet}
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      </div>

      {/* ══ COLUMN 2 & 3: Main Content Area ════════════════════════════════════ */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'row', overflow: 'hidden' }}>

        {/* ── EMPTY STATE (No Contact Selected) ─────────────────────────────────── */}
        {!activeId ? (
          <>
            {/* Middle Column: Overview */}
            <div style={{ flex: 2, borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', background: '#f8fafc' }}>
              <div style={{ padding: '32px 40px' }}>
                <h1 style={{ fontSize: 24, fontWeight: 700, margin: '0 0 24px 0', color: '#0f172a' }}>Today's Overview</h1>

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16, marginBottom: 32 }}>
                  <StatCard title="Total Calls" value={globalSummary?.total_calls ?? 0} icon="fa-phone" color="#3b82f6" bg="#eff6ff" />
                  <StatCard title="Answered"    value={globalSummary?.inbound_calls ?? 0} icon="fa-check" color="#10b981" bg="#ecfdf5" />
                  <StatCard title="Missed"      value={globalSummary?.missed_calls ?? 0} icon="fa-phone-slash" color="#ef4444" bg="#fef2f2" />
                  <StatCard title="Avg Duration" value={fmtDur(globalSummary?.avg_duration_seconds)} icon="fa-clock" color="#8b5cf6" bg="#f5f3ff" />
                </div>

                <h2 style={{ fontSize: 18, fontWeight: 700, margin: '0 0 20px 0', color: '#0f172a' }}>Recent Activity</h2>
                <div style={{ background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0', overflow: 'hidden' }}>
                  {globalLogs.length === 0 && <div style={{ padding: 24, textAlign: 'center', color: '#94a3b8' }}>No recent activity</div>}
                  {globalLogs.map((log: any, i) => {
                    const cname = log.conversation?.contact?.name || log.conversation?.contact?.phone || 'Unknown'
                    const { icon, color, label, bg } = logIcon(log.meta?.call_event, log.direction)
                    return (
                      <div key={log.id} style={{ display: 'flex', alignItems: 'center', padding: '16px 20px', borderBottom: i < globalLogs.length - 1 ? '1px solid #f1f5f9' : 'none' }}>
                        <div style={{ width: 40, height: 40, borderRadius: 10, background: bg, display: 'flex', alignItems: 'center', justifyContent: 'center', color, marginRight: 16 }}>
                          <i className={icon} />
                        </div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a' }}>{cname}</div>
                          <div style={{ fontSize: 13, color: '#64748b', marginTop: 2 }}>{label} {log.meta?.duration ? `· ${fmtDur(log.meta.duration)}` : ''}</div>
                        </div>
                        <div style={{ textAlign: 'right' }}>
                          <div style={{ fontSize: 13, fontWeight: 500, color: '#0f172a' }}>{fmtTime(log.created_at)}</div>
                          <div style={{ fontSize: 12, color: '#94a3b8' }}>{fmtDate(log.created_at)}</div>
                        </div>
                      </div>
                    )
                  })}
                </div>
              </div>
            </div>

            {/* Right Column: Empty State Illustration */}
            <div style={{ flex: 1, background: '#fff', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: 40, textAlign: 'center' }}>
              <div style={{ width: 120, height: 120, borderRadius: '50%', background: '#f1f5f9', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 24 }}>
                <i className="fa-solid fa-users" style={{ fontSize: 40, color: '#94a3b8' }} />
              </div>
              <h3 style={{ fontSize: 18, fontWeight: 600, color: '#0f172a', marginBottom: 12 }}>No Contact Selected</h3>
              <p style={{ fontSize: 14, color: '#64748b', lineHeight: 1.5 }}>Select a contact from the list on the left to view their interaction history, make calls, and add notes.</p>
            </div>
          </>
        ) : (
          /* ── ACTIVE STATE (Contact Selected) ──────────────────────────────────── */
          <>
            {/* Middle Column: Interaction History */}
            <div style={{ flex: 2, display: 'flex', flexDirection: 'column', background: '#f8fafc', borderRight: '1px solid #e2e8f0' }}>

              {/* Profile Header & Actions */}
              <div style={{ padding: '24px 32px', background: '#fff', borderBottom: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 5 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
                  <div style={{ width: 56, height: 56, borderRadius: '50%', background: '#3b82f6', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, fontWeight: 700, color: '#fff' }}>
                    {name.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <h2 style={{ fontSize: 20, fontWeight: 700, margin: '0 0 4px 0', color: '#0f172a' }}>{name}</h2>
                    <div style={{ fontSize: 14, color: '#64748b' }}>
                      <i className="fa-brands fa-whatsapp" style={{ color: '#25d366', marginRight: 6 }} />
                      +{contact?.phone}
                    </div>
                  </div>
                </div>

                {/* Call Control State Machine */}
                <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
                  {call.callState === 'idle' || call.callState === 'checking' ? (
                     <button onClick={call.startCall} disabled={call.callState === 'checking'} style={{ background: '#3b82f6', color: '#fff', border: 'none', borderRadius: 8, padding: '10px 20px', fontSize: 14, fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8, transition: 'background 0.2s' }}>
                       <i className="fa-solid fa-phone" />
                       {call.callState === 'checking' ? 'Checking...' : 'Initiate Call'}
                     </button>
                  ) : call.callState === 'permission_required' ? (
                     <button onClick={call.requestPermission} style={{ background: '#f59e0b', color: '#fff', border: 'none', borderRadius: 8, padding: '10px 20px', fontSize: 14, fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8 }}>
                       <i className="fa-solid fa-bell" />
                       Request Permission
                     </button>
                  ) : call.callState === 'connected' ? (
                     <div style={{ display: 'flex', alignItems: 'center', gap: 12, background: '#ecfdf5', border: '1px solid #10b981', padding: '6px 16px', borderRadius: 30 }}>
                        <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#10b981', animation: 'pulse 1.5s infinite' }} />
                        <span style={{ fontSize: 16, fontWeight: 700, color: '#065f46', width: 60 }}>{fmtDur(call.duration)}</span>

                        <button onClick={call.toggleMute} style={{ width: 36, height: 36, borderRadius: '50%', border: 'none', background: call.isMuted ? '#ef4444' : 'transparent', color: call.isMuted ? '#fff' : '#065f46', cursor: 'pointer' }}>
                          <i className={call.isMuted ? "fa-solid fa-microphone-slash" : "fa-solid fa-microphone"} />
                        </button>

                        <button onClick={call.isRecording ? call.stopRecording : call.startRecording} style={{ width: 36, height: 36, borderRadius: '50%', border: 'none', background: call.isRecording ? '#ef4444' : 'transparent', color: call.isRecording ? '#fff' : '#065f46', cursor: 'pointer' }}>
                          <i className={call.isRecording ? "fa-solid fa-stop" : "fa-solid fa-circle-dot"} />
                        </button>

                        <button onClick={call.endCall} style={{ background: '#ef4444', color: '#fff', border: 'none', borderRadius: 20, padding: '6px 16px', fontSize: 13, fontWeight: 600, cursor: 'pointer', marginLeft: 8 }}>
                          End Call
                        </button>
                     </div>
                  ) : (
                     <button onClick={call.endCall} style={{ background: '#ef4444', color: '#fff', border: 'none', borderRadius: 8, padding: '10px 20px', fontSize: 14, fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8 }}>
                       <i className="fa-solid fa-phone-slash" />
                       Cancel {call.callState}
                     </button>
                  )}
                  <button style={{ width: 40, height: 40, borderRadius: 8, border: '1px solid #e2e8f0', background: '#fff', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <i className="fa-solid fa-calendar-alt" />
                  </button>
                </div>
              </div>

              {/* Interaction History */}
              <div style={{ flex: 1, overflowY: 'auto', padding: '32px', display: 'flex', flexDirection: 'column' }}>
                <h3 style={{ fontSize: 16, fontWeight: 700, margin: '0 0 24px 0', color: '#0f172a' }}>Interaction History</h3>

                {loading ? <div style={{ color: '#94a3b8' }}>Loading...</div> : callLogs.length === 0 ? <div style={{ color: '#94a3b8' }}>No history found</div> : null}

                <div style={{ display: 'flex', flexDirection: 'column', gap: 24, position: 'relative' }}>
                  {/* Timeline Line */}
                  <div style={{ position: 'absolute', left: 20, top: 20, bottom: 20, width: 2, background: '#e2e8f0', zIndex: 0 }} />

                  {callLogs.map(log => {
                    const isNote = log.meta?.is_note || log.meta?.note_type === 'quick_note' || log.body?.startsWith('[Note]') || log.content_type === 'text'

                    if (isNote) {
                      return (
                        <div key={log.id} style={{ display: 'flex', gap: 16, zIndex: 1 }}>
                          <div style={{ width: 40, height: 40, borderRadius: '50%', background: '#f5f3ff', color: '#8b5cf6', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '4px solid #f8fafc', flexShrink: 0 }}>
                            <i className="fa-solid fa-sticky-note" style={{ fontSize: 14 }} />
                          </div>
                          <div style={{ flex: 1, background: '#fff', padding: '16px', borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 1px 2px rgba(0,0,0,0.05)' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
                              <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a' }}>Quick Note</div>
                              <div style={{ fontSize: 12, color: '#94a3b8' }}>{fmtDate(log.created_at)} at {fmtTime(log.created_at)}</div>
                            </div>
                            <div style={{ fontSize: 14, color: '#334155', lineHeight: 1.5 }}>{log.body}</div>
                          </div>
                        </div>
                      )
                    }

                    // Call Log
                    const event = (log.meta?.call_event ?? '').toLowerCase()
                    const { icon, color, label, bg } = logIcon(event, log.direction)
                    const rec = recordings.find(r => r.call_id === log.meta?.call_id)

                    return (
                      <div key={log.id} style={{ display: 'flex', gap: 16, zIndex: 1 }}>
                        <div style={{ width: 40, height: 40, borderRadius: '50%', background: bg, color, display: 'flex', alignItems: 'center', justifyContent: 'center', border: '4px solid #f8fafc', flexShrink: 0 }}>
                          <i className={icon} style={{ fontSize: 14 }} />
                        </div>
                        <div style={{ flex: 1, background: '#fff', padding: '16px', borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 1px 2px rgba(0,0,0,0.05)' }}>
                          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                            <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a' }}>
                              {log.direction === 'inbound' ? 'Inbound Call' : 'Outbound Call'}
                            </div>
                            <div style={{ fontSize: 12, color: '#94a3b8' }}>{fmtDate(log.created_at)} at {fmtTime(log.created_at)}</div>
                          </div>
                          <div style={{ fontSize: 13, color: '#64748b', display: 'flex', gap: 12 }}>
                            <span>Status: <strong style={{ color: '#334155' }}>{label}</strong></span>
                            {log.meta?.duration && <span>Duration: <strong style={{ color: '#334155' }}>{fmtDur(log.meta.duration)}</strong></span>}
                          </div>

                          {/* Recording Player Inline */}
                          {rec && (
                            <div style={{ marginTop: 12, display: 'flex', alignItems: 'center', gap: 12, padding: '10px 12px', background: '#f8fafc', borderRadius: 8, border: '1px solid #e2e8f0' }}>
                              <button onClick={() => playRecording(rec)} style={{ width: 32, height: 32, borderRadius: '50%', border: 'none', background: playingId === rec.id ? '#ef4444' : '#3b82f6', color: '#fff', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                <i className={playingId === rec.id ? "fa-solid fa-pause" : "fa-solid fa-play"} style={{ fontSize: 12 }} />
                              </button>
                              <div style={{ flex: 1, fontSize: 13, color: '#334155', fontWeight: 500 }}>Recording ({fmtDur(rec.duration_seconds)})</div>
                              <button onClick={async () => {
                                const r = await fetch(`/api/whatsapp/call-recording?id=${rec.id}`)
                                const d = await r.json()
                                if (d.signed_url) window.open(d.signed_url, '_blank')
                              }} style={{ background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', padding: 4 }}>
                                <i className="fa-solid fa-download" />
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    )
                  })}
                </div>
              </div>

              {/* Quick Note Input */}
              <div style={{ padding: '24px 32px', background: '#fff', borderTop: '1px solid #e2e8f0', zIndex: 5 }}>
                <h4 style={{ fontSize: 14, fontWeight: 600, color: '#0f172a', margin: '0 0 12px 0' }}>Quick Note</h4>
                <div style={{ position: 'relative' }}>
                  <textarea 
                    value={noteText}
                    onChange={e => setNoteText(e.target.value)}
                    placeholder="Add a note about this contact..."
                    style={{ width: '100%', height: 80, padding: '12px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 14, resize: 'none', fontFamily: 'inherit', background: '#f8fafc' }}
                  />
                  <button 
                    onClick={submitNote}
                    disabled={noteLoading || !noteText.trim()}
                    style={{ position: 'absolute', bottom: 12, right: 12, background: noteText.trim() ? '#3b82f6' : '#cbd5e1', color: '#fff', border: 'none', borderRadius: 6, padding: '6px 14px', fontSize: 13, fontWeight: 600, cursor: noteText.trim() ? 'pointer' : 'not-allowed', transition: 'background 0.2s' }}
                  >
                    {noteLoading ? 'Saving...' : 'Save Note'}
                  </button>
                </div>
              </div>
            </div>

            {/* Right Column: Contact Profile */}
            <div style={{ flex: 1, background: '#fff', padding: 32, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', textAlign: 'center', marginBottom: 32 }}>
                <div style={{ width: 80, height: 80, borderRadius: '50%', background: '#3b82f6', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 32, fontWeight: 700, color: '#fff', marginBottom: 16 }}>
                  {name.charAt(0).toUpperCase()}
                </div>
                <h2 style={{ fontSize: 20, fontWeight: 700, margin: '0 0 8px 0', color: '#0f172a' }}>{name}</h2>
                <div style={{ fontSize: 14, color: '#64748b', marginBottom: 4 }}>Account Tier: {tags.includes('VIP') ? 'Enterprise' : 'Standard'}</div>
                <div style={{ fontSize: 14, color: '#64748b' }}>Location: Shared Location</div>
              </div>

              {/* Tags */}
              <div style={{ marginBottom: 32 }}>
                <h3 style={{ fontSize: 14, fontWeight: 700, color: '#0f172a', textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 12 }}>Tags</h3>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                  {tags.length === 0 ? <span style={{ fontSize: 13, color: '#94a3b8' }}>No tags assigned</span> : null}
                  {tags.map((tag: string) => (
                    <span key={tag} style={{ background: '#f1f5f9', color: '#334155', padding: '4px 10px', borderRadius: 16, fontSize: 12, fontWeight: 500 }}>
                      {tag}
                    </span>
                  ))}
                  {/* Mock tags for UI fidelity */}
                  <span style={{ background: '#f1f5f9', color: '#334155', padding: '4px 10px', borderRadius: 16, fontSize: 12, fontWeight: 500 }}>Decision Maker</span>
                  <span style={{ background: '#f1f5f9', color: '#334155', padding: '4px 10px', borderRadius: 16, fontSize: 12, fontWeight: 500 }}>Q4 Renewal</span>
                </div>
              </div>

              {/* Account Health */}
              <div>
                <h3 style={{ fontSize: 14, fontWeight: 700, color: '#0f172a', textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 16 }}>Account Health</h3>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ fontSize: 14, color: '#64748b' }}>Response Rate</div>
                    <div style={{ fontSize: 14, fontWeight: 600, color: '#10b981' }}>94%</div>
                  </div>
                  <div style={{ width: '100%', height: 6, background: '#f1f5f9', borderRadius: 3, overflow: 'hidden' }}>
                    <div style={{ width: '94%', height: '100%', background: '#10b981' }} />
                  </div>

                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 8 }}>
                    <div style={{ fontSize: 14, color: '#64748b' }}>Total Calls</div>
                    <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a' }}>{summary?.total_calls ?? 0}</div>
                  </div>

                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ fontSize: 14, color: '#64748b' }}>Avg Duration</div>
                    <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a' }}>{fmtDur(summary?.avg_duration_seconds)}</div>
                  </div>
                </div>
              </div>

            </div>
          </>
        )}
      </div>
    </div>
  )
}

function StatCard({ title, value, icon, color, bg }: { title: string, value: string | number, icon: string, color: string, bg: string }) {
  return (
    <div style={{ background: '#fff', borderRadius: 12, padding: 20, border: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <div style={{ fontSize: 14, fontWeight: 500, color: '#64748b' }}>{title}</div>
        <div style={{ width: 32, height: 32, borderRadius: 8, background: bg, color, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <i className={`fa-solid ${icon}`} style={{ fontSize: 14 }} />
        </div>
      </div>
      <div style={{ fontSize: 24, fontWeight: 700, color: '#0f172a' }}>{value}</div>
    </div>
  )
}

'use client'
import { useEffect, useState, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { Contact } from '@/types'

interface CustomField { key: string; label: string; value: string }
interface ContactWithCustom extends Partial<Contact> {
  custom_fields?: CustomField[]
}

const TAG_OPTIONS = ['VIP', 'Lead', 'Hot Lead', 'B2B', 'Repeat Buyer', 'Wholesale', 'Delhi NCR', 'Mumbai', 'Bangalore', 'Enterprise', 'SMB']

const DEFAULT_CUSTOM_FIELD_KEYS = [
  { key: 'company', label: 'Company' },
  { key: 'designation', label: 'Designation' },
  { key: 'gst_number', label: 'GST Number' },
  { key: 'order_count', label: 'Total Orders' },
  { key: 'lifetime_value', label: 'Lifetime Value (₹)' },
  { key: 'city', label: 'City' },
  { key: 'language', label: 'Preferred Language' },
]

export default function ContactsPage() {
  const supabase = createClient()
  const [contacts, setContacts] = useState<any[]>([])
  const [search, setSearch] = useState('')
  const [workspaceId, setWorkspaceId] = useState('')
  const [saving, setSaving] = useState(false)
  const [modal, setModal] = useState<{ open: boolean; mode: 'new' | 'edit'; contact: ContactWithCustom }>({ open: false, mode: 'new', contact: {} })
  const [customFieldDefs, setCustomFieldDefs] = useState(DEFAULT_CUSTOM_FIELD_KEYS)
  const [addingField, setAddingField] = useState(false)
  const [newFieldLabel, setNewFieldLabel] = useState('')
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => { init() }, [])

  async function init() {
    const { data: { session } } = await supabase.auth.getSession()
    if (!session) return
    const { data: p } = await supabase.from('profiles').select('workspace_id').eq('id', session.user.id).single()
    if (!p) return
    setWorkspaceId(p.workspace_id)
    load(p.workspace_id)
  }

  async function load(wsId?: string) {
    const id = wsId || workspaceId
    if (!id) return
    const { data } = await supabase.from('contacts').select('*').eq('workspace_id', id).order('created_at', { ascending: false })
    if (data) setContacts(data)
  }

  function upd(field: string, val: any) {
    setModal(m => ({ ...m, contact: { ...m.contact, [field]: val } }))
  }

  function updCustom(key: string, val: string) {
    const existing = modal.contact.custom_fields ?? []
    const updated = existing.some(f => f.key === key)
      ? existing.map(f => f.key === key ? { ...f, value: val } : f)
      : [...existing, { key, label: customFieldDefs.find(d => d.key === key)?.label ?? key, value: val }]
    upd('custom_fields', updated)
  }

  function getCustomVal(key: string): string {
    return modal.contact.custom_fields?.find(f => f.key === key)?.value ?? ''
  }

  function addCustomField() {
    if (!newFieldLabel.trim()) return
    const key = newFieldLabel.toLowerCase().replace(/\s+/g, '_')
    if (customFieldDefs.some(f => f.key === key)) { alert('Field already exists'); return }
    setCustomFieldDefs(prev => [...prev, { key, label: newFieldLabel.trim() }])
    setNewFieldLabel(''); setAddingField(false)
  }

  async function save() {
    if (!workspaceId) return
    setSaving(true)
    const c = modal.contact
    const row: any = {
      name: c.name || null,
      phone: c.phone ? c.phone.replace(/[\s\-\+\(\)]/g, '') : null,
      email: c.email || null,
      instagram_username: c.instagram_username ? c.instagram_username.replace('@', '') : null,
      facebook_id: c.facebook_id || null,
      tags: c.tags || [],
      notes: c.notes || null,
      meta: { ...(c as any).meta, custom_fields: c.custom_fields ?? [] },
    }

    if (modal.mode === 'new') {
      const { error } = await supabase.from('contacts').insert({ workspace_id: workspaceId, ...row })
      if (error) { alert(error.message); setSaving(false); return }
    } else {
      const { error } = await supabase.from('contacts').update({ ...row, updated_at: new Date().toISOString() }).eq('id', c.id!)
      if (error) { alert(error.message); setSaving(false); return }
    }
    setSaving(false)
    setModal({ open: false, mode: 'new', contact: {} })
    load()
  }

  function openEdit(c: any) {
    setModal({ open: true, mode: 'edit', contact: { ...c, custom_fields: c.meta?.custom_fields ?? [] } })
  }

  async function del(id: string) {
    if (!confirm('Delete this contact?')) return
    await supabase.from('contacts').delete().eq('id', id)
    setContacts(prev => prev.filter(c => c.id !== id))
  }

  async function importCSV(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file || !workspaceId) return
    const text = await file.text()
    const lines = text.trim().split('\n')
    if (lines.length < 2) { alert('CSV must have header + data rows'); return }
    const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/[^a-z_]/g, ''))
    const col = (h: string) => headers.findIndex(x => x.includes(h))
    const ni = col('name'), pi = col('phone'), ei = col('email'), ii = col('insta'), fi = col('facebook'), ti = col('tag')
    const rows = lines.slice(1).map(line => {
      const cols = line.split(',').map(c => c.trim().replace(/^"|"$/g, ''))
      return {
        workspace_id: workspaceId,
        name: ni >= 0 ? cols[ni] || null : null,
        phone: pi >= 0 ? cols[pi]?.replace(/[\s\-\+\(\)]/g, '') || null : null,
        email: ei >= 0 ? cols[ei] || null : null,
        instagram_username: ii >= 0 ? cols[ii]?.replace('@', '') || null : null,
        facebook_id: fi >= 0 ? cols[fi] || null : null,
        tags: ti >= 0 && cols[ti] ? cols[ti].split(';').map(t => t.trim()) : [],
      }
    }).filter(r => r.name || r.phone)
    if (!rows.length) { alert('No valid rows'); return }
    const { error } = await supabase.from('contacts').upsert(rows, { onConflict: 'workspace_id,phone', ignoreDuplicates: false })
    if (error) { alert(error.message); return }
    alert(`✅ Imported ${rows.length} contacts`)
    load()
    if (fileInputRef.current) fileInputRef.current.value = ''
  }

  const filtered = contacts.filter(c =>
    !search ||
    (c.name ?? '').toLowerCase().includes(search.toLowerCase()) ||
    (c.phone ?? '').includes(search) ||
    (c.email ?? '').toLowerCase().includes(search.toLowerCase()) ||
    (c.instagram_username ?? '').toLowerCase().includes(search.toLowerCase())
  )
  const tags = modal.contact.tags ?? []

  return (
    <div className="generic-page">
      <input ref={fileInputRef} type="file" accept=".csv" style={{ display: 'none' }} onChange={importCSV} />
      <div className="page-header">
        <span className="page-title"><i className="fa-solid fa-user-group" style={{ color: 'var(--accent)', marginRight: 8 }} />Contacts</span>
        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn btn-secondary" onClick={() => fileInputRef.current?.click()}><i className="fa-solid fa-file-import" /> Import CSV</button>
          <button className="btn btn-primary" onClick={() => setModal({ open: true, mode: 'new', contact: { tags: [], custom_fields: [] } })}><i className="fa-solid fa-plus" /> New Contact</button>
        </div>
      </div>

      <div className="page-body">
        <div className="stats-grid">
          <div className="stat-card"><div className="stat-label">Total</div><div className="stat-val">{contacts.length}</div></div>
          <div className="stat-card"><div className="stat-label"><i className="fa-brands fa-whatsapp" style={{ color: '#25d366' }} /> WA</div><div className="stat-val">{contacts.filter(c => c.phone).length}</div></div>
          <div className="stat-card"><div className="stat-label"><i className="fa-brands fa-instagram" style={{ color: '#e1306c' }} /> IG</div><div className="stat-val">{contacts.filter(c => c.instagram_username).length}</div></div>
          <div className="stat-card"><div className="stat-label"><i className="fa-brands fa-facebook" style={{ color: '#1877f2' }} /> FB</div><div className="stat-val">{contacts.filter(c => c.facebook_id).length}</div></div>
        </div>
        <div className="contacts-toolbar">
          <div className="search-input-wrap" style={{ width: 280 }}>
            <i className="fa-solid fa-magnifying-glass" />
            <input type="text" placeholder="Search by name, phone, email…" value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <span style={{ fontSize: 11, color: 'var(--text-muted)', marginLeft: 'auto' }}>CSV: name, phone, email, instagram, facebook, tags</span>
        </div>
        <div className="data-table">
          <div className="table-header"><span className="table-title">All Contacts</span><span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{filtered.length} contacts</span></div>
          <table className="tbl">
            <thead><tr><th>Name</th><th>Phone</th><th>Email</th><th>Social</th><th>Tags</th><th>Added</th><th style={{ width: 70 }}></th></tr></thead>
            <tbody>
              {filtered.map(c => (
                <tr key={c.id} style={{ cursor: 'pointer' }} onClick={() => openEdit(c)}>
                  <td className="primary">{c.name || '—'}</td>
                  <td>{c.phone ? <><i className="fa-brands fa-whatsapp" style={{ color: '#25d366', fontSize: 11, marginRight: 4 }} />{c.phone}</> : '—'}</td>
                  <td style={{ fontSize: 12 }}>{c.email || '—'}</td>
                  <td style={{ fontSize: 11 }}>
                    {c.instagram_username && <div><i className="fa-brands fa-instagram" style={{ color: '#e1306c', marginRight: 3 }} />@{c.instagram_username}</div>}
                    {c.facebook_id && <div><i className="fa-brands fa-facebook" style={{ color: '#1877f2', marginRight: 3 }} />{c.facebook_id.slice(0, 12)}…</div>}
                    {!c.instagram_username && !c.facebook_id && '—'}
                  </td>
                  <td>{(c.tags || []).map((t: string) => <span key={t} className="pill green" style={{ marginRight: 3, marginBottom: 2 }}>{t}</span>)}</td>
                  <td style={{ fontSize: 11 }}>{new Date(c.created_at).toLocaleDateString('en-IN')}</td>
                  <td onClick={e => e.stopPropagation()}>
                    <div style={{ display: 'flex', gap: 4 }}>
                      <button className="icon-btn" onClick={() => openEdit(c)}><i className="fa-solid fa-pen" style={{ fontSize: 11 }} /></button>
                      <button className="icon-btn" onClick={() => del(c.id)}><i className="fa-solid fa-trash" style={{ fontSize: 11, color: '#e84040' }} /></button>
                    </div>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr><td colSpan={7} style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)', fontSize: 13 }}>
                  {contacts.length === 0 ? 'Contacts appear when someone messages you, or click New Contact.' : 'No results.'}
                </td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {modal.open && (
        <div className="tpl-modal-overlay open" onClick={() => setModal(m => ({ ...m, open: false }))}>
          <div className="tpl-modal" style={{ maxWidth: 580 }} onClick={e => e.stopPropagation()}>
            <div className="tpl-modal-header">
              <div className="tpl-modal-title">
                <i className={`fa-solid ${modal.mode === 'new' ? 'fa-plus' : 'fa-pen'}`} style={{ color: 'var(--accent)', marginRight: 6, fontSize: 12 }} />
                {modal.mode === 'new' ? 'New Contact' : 'Edit Contact'}
              </div>
              <button className="icon-btn" onClick={() => setModal(m => ({ ...m, open: false }))}><i className="fa-solid fa-xmark" /></button>
            </div>
            <div className="tpl-modal-body" style={{ gap: 0 }}>

              {/* Basic Info */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 10 }}>Basic Info</div>
                <div className="form-row">
                  <div><div className="form-label">Full Name</div><input className="form-input" value={modal.contact.name ?? ''} onChange={e => upd('name', e.target.value)} placeholder="Pintu Kumar" /></div>
                  <div><div className="form-label">Email</div><input className="form-input" type="email" value={modal.contact.email ?? ''} onChange={e => upd('email', e.target.value)} placeholder="email@example.com" /></div>
                </div>
              </div>

              {/* Channels */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 10, paddingTop: 12, borderTop: '1px solid var(--border)' }}>Messaging Channels</div>
                <div className="form-row">
                  <div>
                    <div className="form-label"><i className="fa-brands fa-whatsapp" style={{ color: '#25d366', marginRight: 4 }} />WhatsApp Phone</div>
                    <input className="form-input" value={modal.contact.phone ?? ''} onChange={e => upd('phone', e.target.value)} placeholder="919354231262" />
                    <div style={{ fontSize: 10, color: 'var(--text-muted)', marginTop: 2 }}>With country code, no +</div>
                  </div>
                  <div>
                    <div className="form-label"><i className="fa-brands fa-instagram" style={{ color: '#e1306c', marginRight: 4 }} />Instagram Username</div>
                    <input className="form-input" value={modal.contact.instagram_username ?? ''} onChange={e => upd('instagram_username', e.target.value)} placeholder="username (no @)" />
                  </div>
                </div>
                <div className="form-group">
                  <div className="form-label"><i className="fa-brands fa-facebook" style={{ color: '#1877f2', marginRight: 4 }} />Facebook ID</div>
                  <input className="form-input" value={modal.contact.facebook_id ?? ''} onChange={e => upd('facebook_id', e.target.value)} placeholder="Auto-filled when they message via Facebook" />
                  <div style={{ fontSize: 10, color: 'var(--text-muted)', marginTop: 2 }}>This is set automatically when contact messages via Facebook Messenger</div>
                </div>
              </div>

              {/* Tags */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 10, paddingTop: 12, borderTop: '1px solid var(--border)' }}>Tags</div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                  {TAG_OPTIONS.map(tag => (
                    <div key={tag} onClick={() => upd('tags', tags.includes(tag) ? tags.filter((t: string) => t !== tag) : [...tags, tag])}
                      style={{ padding: '3px 10px', borderRadius: 10, fontSize: 11, cursor: 'pointer', border: '1px solid', borderColor: tags.includes(tag) ? 'var(--accent)' : 'var(--border)', background: tags.includes(tag) ? 'var(--accent-glow)' : 'var(--bg-surface)', color: tags.includes(tag) ? 'var(--accent)' : 'var(--text-secondary)' }}>
                      {tags.includes(tag) && <i className="fa-solid fa-check" style={{ fontSize: 9, marginRight: 4 }} />}{tag}
                    </div>
                  ))}
                </div>
              </div>

              {/* Custom Fields */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ paddingTop: 12, borderTop: '1px solid var(--border)', marginBottom: 10, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                  <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.07em' }}>Custom Fields</div>
                  <button onClick={() => setAddingField(v => !v)} style={{ fontSize: 11, color: 'var(--accent)', background: 'none', border: '1px solid rgba(37,211,102,0.3)', borderRadius: 6, padding: '2px 8px', cursor: 'pointer', fontFamily: 'inherit' }}>
                    <i className="fa-solid fa-plus" style={{ marginRight: 3 }} />Add Field
                  </button>
                </div>

                {addingField && (
                  <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
                    <input className="form-input" style={{ flex: 1 }} value={newFieldLabel} onChange={e => setNewFieldLabel(e.target.value)} placeholder="Field name (e.g. Company, GST Number)" onKeyDown={e => { if (e.key === 'Enter') addCustomField() }} />
                    <button className="btn btn-primary" style={{ padding: '6px 12px' }} onClick={addCustomField}>Add</button>
                    <button className="btn btn-secondary" style={{ padding: '6px 12px' }} onClick={() => { setAddingField(false); setNewFieldLabel('') }}>Cancel</button>
                  </div>
                )}

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 8 }}>
                  {customFieldDefs.map(field => (
                    <div key={field.key}>
                      <div className="form-label" style={{ fontSize: 10 }}>{field.label}</div>
                      <input className="form-input" style={{ padding: '6px 10px', fontSize: 12 }} value={getCustomVal(field.key)} onChange={e => updCustom(field.key, e.target.value)} placeholder={field.label} />
                    </div>
                  ))}
                </div>
              </div>

              {/* Notes */}
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 8, paddingTop: 12, borderTop: '1px solid var(--border)' }}>Notes</div>
                <textarea className="form-input" rows={2} value={modal.contact.notes ?? ''} onChange={e => upd('notes', e.target.value)} placeholder="Internal notes about this contact…" style={{ resize: 'vertical' }} />
              </div>
            </div>
            <div className="tpl-modal-footer">
              <button className="btn btn-secondary" onClick={() => setModal(m => ({ ...m, open: false }))}>Cancel</button>
              <button className="btn btn-primary" onClick={save} disabled={saving}>
                {saving ? 'Saving…' : modal.mode === 'new' ? 'Create Contact' : 'Save Changes'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'
import { useEffect, useCallback, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useInboxStore } from '@/stores/useInboxStore'
import { useAuthStore } from '@/stores/useAuthStore'
import ConversationPanel from '@/components/inbox/ConversationPanel'
import ChatWindow from '@/components/inbox/ChatWindow'
import InfoPanel from '@/components/inbox/InfoPanel'
import type { Conversation } from '@/types'

export default function InboxPage() {
  const supabase = createClient()
  const { setConversations, activeConversationId } = useInboxStore()
  const { setProfile } = useAuthStore()
  const [loadError, setLoadError] = useState<string | null>(null)
  const [workspaceId, setWorkspaceId] = useState<string | null>(null)

  const loadData = useCallback(async () => {
    setLoadError(null)

    const { data: { session } } = await supabase.auth.getSession()
    if (!session) { setLoadError('Not logged in'); return }

    const { data: profile, error: profileErr } = await supabase
      .from('profiles')
      .select('id, workspace_id, full_name, email, role, avatar_url, is_online, created_at')
      .eq('id', session.user.id)
      .single()

    if (profileErr || !profile) {
      const code = profileErr?.code
      const msg = profileErr?.message ?? 'unknown error'
      console.error('[Inbox] Profile error:', code, msg)

      // PGRST116 = "no rows returned" by .single() — genuine missing profile
      if (code === 'PGRST116') {
        setLoadError(`Profile row missing for user ${session.user.id}.\nCheck the profiles table in Supabase.`)
      } else {
        setLoadError(`Could not load profile.\nError [${code}]: ${msg}`)
      }
      return
    }

    setProfile(profile)
    setWorkspaceId(profile.workspace_id)

    // Load conversations WITHOUT the problematic FK hint
    const { data: convs, error: convErr } = await supabase
      .from('conversations')
      .select(`
        id, workspace_id, contact_id, channel_id, platform,
        external_id, title, status, assigned_to, is_pinned,
        last_message, last_message_at, unread_count, tags, meta,
        created_at, updated_at,
        contact:contacts(
          id, workspace_id, name, phone, email,
          instagram_username, facebook_id, avatar_url, tags,
          notes, meta, created_at, updated_at
        ),
        channel:channels(
          id, workspace_id, platform, name,
          external_id, is_active, meta, created_at
        )
      `)
      .eq('workspace_id', profile.workspace_id)
      .order('last_message_at', { ascending: false })
      .limit(100)

    if (convErr) {
      console.error('[Inbox] Conversations error:', convErr.message)
      setLoadError(`Error loading conversations: ${convErr.message}`)
      return
    }

    // Load assignees separately to avoid FK ambiguity
    const assigneeIds = [...new Set(
      (convs ?? []).map(c => c.assigned_to).filter(Boolean) as string[]
    )]

    let assigneeMap: Record<string, any> = {}
    if (assigneeIds.length > 0) {
      const { data: assignees } = await supabase
        .from('profiles')
        .select('id, full_name, avatar_url, role')
        .in('id', assigneeIds)
      if (assignees) assigneeMap = Object.fromEntries(assignees.map(a => [a.id, a]))
    }

    const merged = (convs ?? []).map(c => ({
      ...c,
      // Supabase returns joined relations as arrays; unwrap to single objects
      contact: Array.isArray(c.contact) ? (c.contact[0] ?? null) : c.contact,
      channel: Array.isArray(c.channel) ? (c.channel[0] ?? null) : c.channel,
      assignee: c.assigned_to ? (assigneeMap[c.assigned_to] ?? null) : null,
    }))

    console.log(`[Inbox] Loaded ${merged.length} conversations`)
    setConversations(merged as Conversation[])
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => { loadData() }, [loadData])

  // Realtime subscription for new conversations / updates
  useEffect(() => {
    if (!workspaceId) return
    const ch = supabase
      .channel(`inbox-realtime-${workspaceId}`)
      .on('postgres_changes', {
        event: '*', schema: 'public', table: 'conversations',
        filter: `workspace_id=eq.${workspaceId}`,
      }, () => loadData())
      .subscribe()
    return () => { supabase.removeChannel(ch) }
  }, [workspaceId, loadData])

  if (loadError) {
    return (
      <div className="page-inbox" style={{ alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 16, padding: 32 }}>
        <i className="fa-solid fa-circle-exclamation" style={{ fontSize: 40, color: 'var(--accent4)', opacity: 0.7 }} />
        <p style={{ fontSize: 13, color: 'var(--text-secondary)', textAlign: 'center', maxWidth: 440, lineHeight: 1.7, whiteSpace: 'pre-line' }}>
          {loadError}
        </p>
        <button className="btn btn-secondary" onClick={loadData}>
          <i className="fa-solid fa-rotate" /> Retry
        </button>
      </div>
    )
  }

  return (
    <div className="page-inbox">
      <ConversationPanel onRefresh={loadData} />
      {activeConversationId ? (
        <>
          <ChatWindow />
          <InfoPanel />
        </>
      ) : (
        <div className="empty-inbox">
          <i className="fa-solid fa-comments" />
          <p>Select a conversation to start</p>
        </div>
      )}
    </div>
  )
}

'use client'
import { useState } from 'react'
import SettingsShell from '@/components/settings/SettingsShell'
import { useRouter } from 'next/navigation'

type Substatus = { id: number; name: string; color?: string }
type Stage = { id: number; name: string; enabled: boolean; substatuses: Substatus[]; isWon?: boolean; isLost?: boolean }

const INITIAL_STAGES: Stage[] = [
  {
    id: 1, name: 'Lead', enabled: true,
    substatuses: [
      { id: 101, name: 'New' },
      { id: 102, name: 'In Progress' },
      { id: 103, name: 'Not Responded' },
      { id: 104, name: 'Scheduled for later' },
    ],
  },
  {
    id: 2, name: 'Sales Qualified Lead', enabled: true,
    substatuses: [
      { id: 201, name: 'Qualified' },
      { id: 202, name: 'Lost', color: '#e84040' },
    ],
  },
  {
    id: 3, name: 'New Customer', enabled: true,
    substatuses: [
      { id: 301, name: 'Negotiation' },
      { id: 302, name: 'Awaiting Client Input' },
      { id: 303, name: 'Scope Shared' },
      { id: 304, name: 'Decision Pending' },
    ],
  },
  {
    id: 4, name: 'Customer', enabled: true,
    substatuses: [
      { id: 401, name: 'Won', color: '#2fe774' },
      { id: 402, name: 'Churned', color: '#e84040' },
    ],
  },
]

function Toggle({ value, onChange }: { value: boolean; onChange: (v: boolean) => void }) {
  return (
    <div onClick={e => { e.stopPropagation(); onChange(!value) }} style={{ width: 32, height: 18, borderRadius: 9, background: value ? 'var(--accent)' : 'var(--bg-surface2)', border: '1px solid var(--border)', cursor: 'pointer', position: 'relative', transition: 'background 0.2s', flexShrink: 0 }}>
      <div style={{ width: 12, height: 12, borderRadius: '50%', background: '#fff', position: 'absolute', top: 2, left: value ? 16 : 2, transition: 'left 0.2s', boxShadow: '0 1px 3px rgba(0,0,0,0.3)' }} />
    </div>
  )
}

function SubstatusCard({ sub, onDelete, onRename }: { sub: Substatus; onDelete: () => void; onRename: (name: string) => void }) {
  const [editing, setEditing] = useState(false)
  const [val, setVal] = useState(sub.name)

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '5px 8px', background: 'var(--bg-surface)', border: '1px solid var(--border)', borderRadius: 7, marginBottom: 4, minWidth: 0 }}>
      <i className="fa-solid fa-grip-dots-vertical" style={{ color: 'var(--text-muted)', fontSize: 9, cursor: 'grab', flexShrink: 0 }} />
      <div style={{ width: 8, height: 8, borderRadius: '50%', background: sub.color ?? 'var(--text-muted)', flexShrink: 0 }} />
      {editing ? (
        <input
          autoFocus
          value={val}
          onChange={e => setVal(e.target.value)}
          onBlur={() => { onRename(val); setEditing(false) }}
          onKeyDown={e => { if (e.key === 'Enter') { onRename(val); setEditing(false) } if (e.key === 'Escape') { setVal(sub.name); setEditing(false) } }}
          style={{ flex: 1, background: 'transparent', border: 'none', outline: 'none', fontSize: 11, color: 'var(--text-primary)', fontFamily: 'DM Sans, sans-serif', minWidth: 0 }}
        />
      ) : (
        <span onDoubleClick={() => setEditing(true)} style={{ flex: 1, fontSize: 11, color: sub.color ? sub.color : 'var(--text-secondary)', fontWeight: sub.color ? 700 : 500, cursor: 'text', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{sub.name}</span>
      )}
      <button onClick={onDelete} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', fontSize: 9, padding: 0, flexShrink: 0, opacity: 0.5, lineHeight: 1 }}
        onMouseEnter={e => (e.currentTarget.style.opacity = '1')}
        onMouseLeave={e => (e.currentTarget.style.opacity = '0.5')}
      >
        <i className="fa-solid fa-xmark" />
      </button>
    </div>
  )
}

function StageCard({ stage, onToggle, onRename, onDelete, onAddStatus, onDeleteStatus, onRenameStatus, isLast }:
  { stage: Stage; onToggle: () => void; onRename: (name: string) => void; onDelete: () => void; onAddStatus: (name: string) => void; onDeleteStatus: (id: number) => void; onRenameStatus: (id: number, name: string) => void; isLast: boolean }) {
  const [editingName, setEditingName] = useState(false)
  const [nameVal, setNameVal] = useState(stage.name)
  const [newStatus, setNewStatus] = useState('')
  const [addingStatus, setAddingStatus] = useState(false)

  return (
    <div style={{ display: 'flex', alignItems: 'flex-start', gap: 0 }}>
      <div style={{ background: 'var(--bg-panel)', border: `1px solid ${stage.enabled ? 'var(--border)' : 'rgba(255,255,255,0.06)'}`, borderRadius: 12, width: 200, minWidth: 200, padding: '12px 12px 10px', opacity: stage.enabled ? 1 : 0.5, transition: 'all 0.2s', flexShrink: 0 }}>
        {/* Stage header */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <i className="fa-solid fa-grip-dots-vertical" style={{ color: 'var(--text-muted)', fontSize: 10, cursor: 'grab' }} />
            {editingName ? (
              <input
                autoFocus
                value={nameVal}
                onChange={e => setNameVal(e.target.value)}
                onBlur={() => { onRename(nameVal); setEditingName(false) }}
                onKeyDown={e => { if (e.key === 'Enter') { onRename(nameVal); setEditingName(false) } }}
                style={{ flex: 1, background: 'var(--bg-surface)', border: '1px solid var(--border-active)', borderRadius: 6, padding: '2px 6px', fontSize: 12, fontWeight: 700, color: 'var(--text-primary)', outline: 'none', fontFamily: 'DM Sans, sans-serif', width: 110 }}
              />
            ) : (
              <span onDoubleClick={() => setEditingName(true)} style={{ fontSize: 12, fontWeight: 700, color: 'var(--text-primary)', cursor: 'text', flex: 1 }}>{stage.name}</span>
            )}
          </div>
          <Toggle value={stage.enabled} onChange={onToggle} />
        </div>

        {/* Substatuses */}
        <div style={{ maxHeight: 200, overflowY: 'auto' }}>
          {stage.substatuses.map(sub => (
            <SubstatusCard
              key={sub.id}
              sub={sub}
              onDelete={() => onDeleteStatus(sub.id)}
              onRename={name => onRenameStatus(sub.id, name)}
            />
          ))}
        </div>

        {/* Add status */}
        {addingStatus ? (
          <div style={{ marginTop: 6 }}>
            <input
              autoFocus
              className="form-input"
              placeholder="Status name"
              value={newStatus}
              onChange={e => setNewStatus(e.target.value)}
              onKeyDown={e => { if (e.key === 'Enter' && newStatus) { onAddStatus(newStatus); setNewStatus(''); setAddingStatus(false) } if (e.key === 'Escape') { setNewStatus(''); setAddingStatus(false) } }}
              style={{ fontSize: 11, padding: '5px 8px', marginBottom: 4 }}
            />
            <div style={{ display: 'flex', gap: 4 }}>
              <button onClick={() => { if (newStatus) { onAddStatus(newStatus); setNewStatus('') }; setAddingStatus(false) }} style={{ flex: 1, padding: '4px', background: 'var(--accent)', border: 'none', borderRadius: 6, cursor: 'pointer', fontSize: 11, fontWeight: 600, color: '#000', fontFamily: 'DM Sans, sans-serif' }}>Add</button>
              <button onClick={() => { setNewStatus(''); setAddingStatus(false) }} style={{ padding: '4px 8px', background: 'var(--bg-surface)', border: '1px solid var(--border)', borderRadius: 6, cursor: 'pointer', fontSize: 11, color: 'var(--text-muted)', fontFamily: 'DM Sans, sans-serif' }}>✕</button>
            </div>
          </div>
        ) : (
          <button onClick={() => setAddingStatus(true)} style={{ width: '100%', marginTop: 6, padding: '5px', background: 'none', border: '1px dashed var(--border)', borderRadius: 7, cursor: 'pointer', fontSize: 11, color: 'var(--text-muted)', fontFamily: 'DM Sans, sans-serif', transition: 'all 0.15s' }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.color = 'var(--accent)' }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.color = 'var(--text-muted)' }}>
            + Add status
          </button>
        )}

        {/* Delete stage */}
        <button onClick={onDelete} style={{ width: '100%', marginTop: 6, padding: '4px', background: 'none', border: 'none', cursor: 'pointer', fontSize: 10, color: 'var(--text-muted)', fontFamily: 'DM Sans, sans-serif', opacity: 0.5, transition: 'opacity 0.15s' }}
          onMouseEnter={e => (e.currentTarget.style.opacity = '1')}
          onMouseLeave={e => (e.currentTarget.style.opacity = '0.5')}>
          <i className="fa-solid fa-trash" style={{ marginRight: 4, color: '#e84040' }} />Remove stage
        </button>
      </div>

      {/* Arrow connector */}
      {!isLast && (
        <div style={{ display: 'flex', alignItems: 'center', padding: '0 8px', alignSelf: 'center', flexShrink: 0 }}>
          <div style={{ width: 20, height: 2, background: 'var(--border)' }} />
          <i className="fa-solid fa-chevron-right" style={{ color: 'var(--text-muted)', fontSize: 10 }} />
        </div>
      )}
    </div>
  )
}

export default function LifecycleStagesPage() {
  const router = useRouter()
  const [stages, setStages] = useState<Stage[]>(INITIAL_STAGES)
  const [showAddStage, setShowAddStage] = useState(false)
  const [newStageName, setNewStageName] = useState('')
  const [saving, setSaving] = useState(false)
  const [rules, setRules] = useState([
    { id: 1, enabled: true, trigger: 'a deal is added', targetStage: 'Lead' },
    { id: 2, enabled: true, trigger: 'a deal is won', targetStage: 'Customer' },
  ])

  function updateStage(id: number, patch: Partial<Stage>) {
    setStages(prev => prev.map(s => s.id === id ? { ...s, ...patch } : s))
  }

  function addStatus(stageId: number, name: string) {
    setStages(prev => prev.map(s => s.id === stageId ? { ...s, substatuses: [...s.substatuses, { id: Date.now(), name }] } : s))
  }

  function deleteStatus(stageId: number, subId: number) {
    setStages(prev => prev.map(s => s.id === stageId ? { ...s, substatuses: s.substatuses.filter(x => x.id !== subId) } : s))
  }

  function renameStatus(stageId: number, subId: number, name: string) {
    setStages(prev => prev.map(s => s.id === stageId ? { ...s, substatuses: s.substatuses.map(x => x.id === subId ? { ...x, name } : x) } : s))
  }

  return (
    <SettingsShell>
      <div style={{ padding: 28 }}>
        {/* Breadcrumb */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12, color: 'var(--text-muted)', marginBottom: 20 }}>
          <span style={{ cursor: 'pointer', color: 'var(--text-secondary)' }} onClick={() => router.push('/settings/admin')}>Admin Settings</span>
          <i className="fa-solid fa-chevron-right" style={{ fontSize: 9 }} />
          <span style={{ color: 'var(--text-primary)' }}>Contact Lifecycle Stages</span>
        </div>

        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 24 }}>
          <div style={{ display: 'flex', gap: 14, alignItems: 'flex-start' }}>
            <div style={{ width: 44, height: 44, borderRadius: 12, background: 'var(--accent-glow)', border: '1px solid var(--border-active)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
              <i className="fa-solid fa-arrow-right-arrow-left" style={{ color: 'var(--accent)', fontSize: 18 }} />
            </div>
            <div>
              <div style={{ fontSize: 22, fontWeight: 700, fontFamily: "'Space Grotesk', sans-serif", marginBottom: 4 }}>Contact Lifecycle Stages</div>
              <div style={{ fontSize: 12.5, color: 'var(--text-secondary)', lineHeight: 1.6, maxWidth: 600 }}>
                Customize lifecycle stages: rename, reorder or disable them. Add new stages that reflect your business process. All statuses within a stage are customizable.
              </div>
            </div>
          </div>
          <a style={{ fontSize: 12, color: 'var(--accent)', cursor: 'pointer', textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 5, marginTop: 4 }}>
            <i className="fa-solid fa-arrow-up-right-from-square" style={{ fontSize: 10 }} />Learn more
          </a>
        </div>

        {/* Active stages heading */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--text-primary)' }}>Active stages</div>
          <button className="btn btn-primary" style={{ fontSize: 12 }} onClick={() => setShowAddStage(true)}>
            <i className="fa-solid fa-plus" /> Add lifecycle stage
          </button>
        </div>

        {/* Add stage modal */}
        {showAddStage && (
          <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.55)', zIndex: 3000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border)', borderRadius: 16, width: 420, padding: 24, boxShadow: '0 24px 80px rgba(0,0,0,0.5)' }}>
              <div style={{ fontSize: 15, fontWeight: 700, fontFamily: "'Space Grotesk', sans-serif", marginBottom: 16 }}>Add Lifecycle Stage</div>
              <div style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: 6 }}>Stage Name</div>
              <input className="form-input" placeholder="e.g. Evangelist, MQL" value={newStageName} onChange={e => setNewStageName(e.target.value)} style={{ marginBottom: 16 }} />
              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                <button className="btn btn-secondary" onClick={() => setShowAddStage(false)}>Cancel</button>
                <button className="btn btn-primary" onClick={() => {
                  if (newStageName) {
                    setStages(prev => [...prev, { id: Date.now(), name: newStageName, enabled: true, substatuses: [{ id: Date.now() + 1, name: 'New' }] }])
                    setNewStageName(''); setShowAddStage(false)
                  }
                }}>Add Stage</button>
              </div>
            </div>
          </div>
        )}

        {/* Pipeline canvas */}
        <div style={{ overflowX: 'auto', paddingBottom: 20 }}>
          <div style={{ display: 'flex', gap: 0, alignItems: 'flex-start', minWidth: 'max-content', padding: '4px 2px 12px' }}>
            {stages.map((stage, i) => (
              <StageCard
                key={stage.id}
                stage={stage}
                isLast={i === stages.length - 1}
                onToggle={() => updateStage(stage.id, { enabled: !stage.enabled })}
                onRename={name => updateStage(stage.id, { name })}
                onDelete={() => setStages(prev => prev.filter(s => s.id !== stage.id))}
                onAddStatus={name => addStatus(stage.id, name)}
                onDeleteStatus={subId => deleteStatus(stage.id, subId)}
                onRenameStatus={(subId, name) => renameStatus(stage.id, subId, name)}
              />
            ))}
          </div>
        </div>

        {/* Rules section */}
        <div style={{ marginTop: 8 }}>
          <div style={{ fontSize: 16, fontWeight: 700, fontFamily: "'Space Grotesk', sans-serif", marginBottom: 16 }}>Rules for changing stages</div>
          <div className="form-section" style={{ maxWidth: 680 }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {rules.map(rule => (
                <div key={rule.id} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '12px 14px', background: 'var(--bg-surface)', border: '1px solid var(--border)', borderRadius: 10 }}>
                  <input
                    type="checkbox"
                    checked={rule.enabled}
                    onChange={() => setRules(prev => prev.map(r => r.id === rule.id ? { ...r, enabled: !r.enabled } : r))}
                    style={{ accentColor: 'var(--accent)', width: 16, height: 16, flexShrink: 0 }}
                  />
                  <span style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                    Whenever <strong style={{ color: 'var(--text-primary)' }}>{rule.trigger}</strong>, change contact's stage to
                  </span>
                  <select
                    value={rule.targetStage}
                    onChange={e => setRules(prev => prev.map(r => r.id === rule.id ? { ...r, targetStage: e.target.value } : r))}
                    style={{ background: 'var(--bg-panel)', border: '1px solid var(--border)', borderRadius: 8, padding: '4px 10px', fontSize: 13, color: 'var(--text-primary)', cursor: 'pointer', outline: 'none', fontFamily: 'DM Sans, sans-serif' }}
                  >
                    {stages.map(s => <option key={s.id}>{s.name}</option>)}
                  </select>
                  <button onClick={() => setRules(prev => prev.filter(r => r.id !== rule.id))} style={{ marginLeft: 'auto', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', fontSize: 12, padding: 0 }}>
                    <i className="fa-solid fa-xmark" />
                  </button>
                </div>
              ))}

              <button onClick={() => setRules(prev => [...prev, { id: Date.now(), enabled: true, trigger: 'a form is submitted', targetStage: stages[0]?.name ?? '' }])}
                style={{ padding: '8px 14px', background: 'none', border: '1px dashed var(--border)', borderRadius: 10, cursor: 'pointer', fontSize: 12, color: 'var(--text-muted)', fontFamily: 'DM Sans, sans-serif', textAlign: 'left', transition: 'all 0.15s', display: 'flex', alignItems: 'center', gap: 7 }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.color = 'var(--accent)' }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--border)'; e.currentTarget.style.color = 'var(--text-muted)' }}>
                <i className="fa-solid fa-plus" /> Add rule
              </button>
            </div>

            <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
              <button className="btn btn-primary" onClick={() => { setSaving(true); setTimeout(() => setSaving(false), 1200) }}>
                {saving ? <><i className="fa-solid fa-spinner fa-spin" /> Saving…</> : 'Save'}
              </button>
              <button className="btn btn-secondary">Cancel</button>
            </div>
          </div>
        </div>
      </div>
    </SettingsShell>
  )
}

'use client'
import { useEffect, useState, useCallback, useRef } from 'react'
import { createClient } from '@/lib/supabase/client'
import FlowBuilder from '@/components/flows/FlowBuilder'
import { convertToMetaJSON } from '@/lib/flowConverter'

const WA_LANGUAGES = [
  { code: 'en_US', label: 'English (US)' }, { code: 'en_GB', label: 'English (UK)' },
  { code: 'hi',    label: 'Hindi'         }, { code: 'mr',    label: 'Marathi'      },
  { code: 'gu',    label: 'Gujarati'      }, { code: 'ta',    label: 'Tamil'        },
  { code: 'te',    label: 'Telugu'        }, { code: 'kn',    label: 'Kannada'      },
  { code: 'bn',    label: 'Bengali'       }, { code: 'pa',    label: 'Punjabi'      },
  { code: 'ml',    label: 'Malayalam'     }, { code: 'ur',    label: 'Urdu'         },
  { code: 'ar',    label: 'Arabic'        }, { code: 'es',    label: 'Spanish'      },
  { code: 'pt_BR', label: 'Portuguese (BR)' }, { code: 'fr', label: 'French'       },
  { code: 'de',    label: 'German'        }, { code: 'it',    label: 'Italian'      },
