              <p style={{ marginTop: 16 }}>We may update this policy from time to time. Material changes will be communicated via email and in-app notification. Your continued use of the platform following any update constitutes acceptance of the revised policy.</p>
            </div>
          </div>

        </main>
      </div>
    </>
  )
}

'use client'
import { useState } from 'react'

// ── Types ──────────────────────────────────────────────────────────────────────
type ComponentType =
  | 'heading' | 'text' | 'input' | 'email'
  | 'phone' | 'dropdown' | 'date' | 'button'

interface Block {
  id: string
  type: ComponentType
  label?: string
  value?: string
  required?: boolean
  placeholder?: string
  options?: { id: string; title: string }[]

  action?: 'next' | 'submit'
  targetScreen?: string
}

interface Screen {
  id: string
  title: string
  blocks: Block[]
  nextScreen?: string
}

// ── WhatsApp Flow JSON Generator ───────────────────────────────────────────────
// Maps Screen[] → Meta WhatsApp Flow JSON v6.1
// Usage: POST /api/flows { action: 'update_json', flow_json: generateFlowJSON(screens) }
export function generateFlowJSON(screens: Screen[]): object {
  const waScreens = screens.map((s, idx) => {
    const nextSc = s.nextScreen ?? screens[idx + 1]?.id ?? null
    const formChildren: any[] = []

    s.blocks.forEach(b => {
      switch (b.type) {
        case 'heading':
          formChildren.push({ type: 'TextHeading', text: b.label ?? '' })
          break
        case 'text':
          formChildren.push({ type: 'TextBody', text: b.label ?? '' })
          break
        case 'input':
        case 'email':
        case 'phone':
          formChildren.push({
            type: 'TextInput',
            label: b.label ?? '',
            name: b.id,
            required: b.required ?? false,
            'input-type': b.type === 'email' ? 'email' : b.type === 'phone' ? 'phone' : 'text',
            ...(b.placeholder ? { 'helper-text': b.placeholder } : {}),
          })
          break
        case 'dropdown':
          formChildren.push({
            type: 'Dropdown',
            label: b.label ?? '',
            name: b.id,
            required: b.required ?? false,
            'data-source': (b.options ?? []).map(o => ({ id: o.id, title: o.title })),
          })
          break
        case 'date':
          formChildren.push({
            type: 'DatePicker',
            label: b.label ?? '',
            name: b.id,
            required: b.required ?? false,
          })
          break
        case 'button':
          formChildren.push({
            type: 'Footer',
            label: b.label ?? (nextSc ? 'Next' : 'Submit'),
            'on-click-action': nextSc
              ? { name: 'navigate', next: { type: 'screen', name: nextSc }, payload: {} }
              : { name: 'complete', payload: {} },
          })
          break
      }
    })

    // Auto-insert Footer if no button block defined
    if (!s.blocks.some(b => b.type === 'button')) {
      formChildren.push({
        type: 'Footer',
        label: nextSc ? 'Next' : 'Submit',
        'on-click-action': nextSc
          ? { name: 'navigate', next: { type: 'screen', name: nextSc }, payload: {} }
          : { name: 'complete', payload: {} },
      })
    }

    return {
      id: s.id,
      title: s.title,
      data: {},
      layout: {
        type: 'SingleColumnLayout',
        children: [{
          type: 'Form',
          name: 'form',
          children: formChildren,
        }],
      },
    }
  })

  return { version: '6.1', screens: waScreens }
}

// ── Component Palette Config ───────────────────────────────────────────────────
const PALETTE: { type: ComponentType; icon: string; label: string; desc: string }[] = [
  { type: 'heading',  icon: 'H1', label: 'Heading',    desc: 'Bold title text'       },
  { type: 'text',     icon: '¶',  label: 'Body Text',  desc: 'Paragraph description'  },
  { type: 'input',    icon: 'Aa', label: 'Text Input', desc: 'Free text field'        },
  { type: 'email',    icon: '@',  label: 'Email',      desc: 'Email address field'    },
  { type: 'phone',    icon: '☎',  label: 'Phone',      desc: 'Phone number field'     },
  { type: 'dropdown', icon: '▾',  label: 'Dropdown',   desc: 'Single-select list'     },
  { type: 'date',     icon: '⬚',  label: 'Date',       desc: 'Date picker'            },
  { type: 'button',   icon: '▶',  label: 'CTA Button', desc: 'Navigate or submit'     },
]

const TYPE_COLOR: Record<ComponentType, string> = {
  heading:  '#00A884',
  text:     '#00A884',
  input:    '#25D366',
  email:    '#25D366',
  phone:    '#25D366',
  dropdown: '#128C7E',
  date:     '#128C7E',
  button:   '#075E54',
}

// ── Phone Preview ──────────────────────────────────────────────────────────────
function BlockPreview({ b }: { b: Block }) {
  const mb = { marginBottom: 7 }
  const lbl: React.CSSProperties = { fontSize: 9, color: '#00A884', marginBottom: 3 }
  const inp: React.CSSProperties = {
    background: '#2A3942', borderRadius: 5, padding: '5px 7px',
    fontSize: 10, color: '#8696A0', border: '1px solid #374045',
    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
  }
  switch (b.type) {
    case 'heading':  return <div style={{ ...mb, fontWeight: 700, fontSize: 13, color: '#E9EDEF' }}>{b.label || 'Heading'}</div>
    case 'text':     return <div style={{ ...mb, fontSize: 10, color: '#8696A0', lineHeight: 1.5 }}>{b.label || 'Body text'}</div>
    case 'input':    return <div style={mb}><div style={lbl}>{b.label}</div><div style={inp}>{b.placeholder || 'Enter text...'}</div></div>
    case 'email':    return <div style={mb}><div style={lbl}>{b.label}</div><div style={inp}>email@example.com</div></div>
    case 'phone':    return <div style={mb}><div style={lbl}>{b.label}</div><div style={inp}>+91 99999 99999</div></div>
    case 'dropdown': return <div style={mb}><div style={lbl}>{b.label}</div><div style={inp}><span>Select...</span><span>▾</span></div></div>
    case 'date':     return <div style={mb}><div style={lbl}>{b.label}</div><div style={inp}><span>DD / MM / YYYY</span><span style={{ fontSize: 9 }}>⬚</span></div></div>
    case 'button':   return <div style={{ background: '#00A884', borderRadius: 16, padding: '7px', textAlign: 'center', fontSize: 11, fontWeight: 700, color: '#fff', marginTop: 8 }}>{b.label || 'Submit'}</div>
    default:         return null
  }
}

function PhonePreview({ screen }: { screen: Screen }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '10px 4px 14px' }}>
      <div style={{
        width: 188, background: '#0D1117', borderRadius: 22,
        padding: '8px 4px',
        border: '1px solid #2A3942',
        boxShadow: '0 0 0 4px #161b22, 0 8px 20px rgba(0,0,0,0.5)',
      }}>
        <div style={{ width: 30, height: 3, background: '#2A3942', borderRadius: 2, margin: '0 auto 5px' }} />
        <div style={{ background: '#0B141A', borderRadius: 14, overflow: 'hidden', minHeight: 300 }}>
          <div style={{ background: '#202C33', padding: '7px 9px', display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{
              width: 22, height: 22, borderRadius: '50%', background: '#00A884',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 9, fontWeight: 700, color: '#fff', flexShrink: 0,
            }}>B</div>
            <div>
              <div style={{ fontSize: 9, fontWeight: 600, color: '#E9EDEF', lineHeight: 1.2 }}>BizInbox</div>
              <div style={{ fontSize: 7.5, color: '#8696A0' }}>Form · {screen.title}</div>
            </div>
          </div>
          <div style={{ padding: '10px 9px 6px' }}>
            {screen.blocks.length === 0
              ? <div style={{ textAlign: 'center', color: '#8696A0', fontSize: 10, paddingTop: 30 }}>No components yet</div>
              : screen.blocks.map(b => <BlockPreview key={b.id} b={b} />)
            }
          </div>
        </div>
        <div style={{ width: 40, height: 3, background: '#2A3942', borderRadius: 2, margin: '5px auto 0' }} />
      </div>
    </div>
  )
}

// ── Main Component ─────────────────────────────────────────────────────────────
export default function FlowBuilder({
  value,
  onChange,
}: {
  value: Screen[]
  onChange: (val: Screen[]) => void
}) {
  const [selectedScreen, setSelectedScreen] = useState(0)
  const [selectedBlockId, setSelectedBlockId] = useState<string | null>(null)

  const screen = value?.[selectedScreen]
  const selectedBlock =
  screen?.blocks?.find((b) => b.id === selectedBlockId) ?? null

  if (!screen || !Array.isArray(screen.blocks)) {
  return (
    <div style={{ padding: 20, color: 'var(--text-muted)' }}>
      Invalid flow data. Please create or reload flow.
    </div>
  )
}

  // ── Helpers ────────────────────────────────────────────────────────────────
  function updateScreen(updated: Screen) {
    const ns = [...value]
    ns[selectedScreen] = updated
    onChange(ns)
  }

  function addBlock(type: ComponentType) {
    const pal = PALETTE.find(p => p.type === type)!
const newBlock: Block = {
  id: `blk_${Date.now()}`,
  type,
  label: pal.label,

  ...(type === 'button'
    ? {
        action: 'submit'
      }
    : {}),

  ...(type === 'dropdown'
    ? {
        options: [
          { id: 'opt1', title: 'Option 1' },
          { id: 'opt2', title: 'Option 2' }
        ]
      }
    : {})
}
    // Always insert before existing button blocks
    const btns   = screen.blocks.filter(b => b.type === 'button')
    const others  = screen.blocks.filter(b => b.type !== 'button')
    updateScreen({ ...screen, blocks: [...others, newBlock, ...btns] })
    setSelectedBlockId(newBlock.id)
  }

  function removeBlock(id: string) {
    updateScreen({ ...screen, blocks: screen.blocks.filter(b => b.id !== id) })
    if (selectedBlockId === id) setSelectedBlockId(null)
  }

  function moveBlock(id: string, dir: -1 | 1) {
    const blocks = [...screen.blocks]
    const idx = blocks.findIndex(b => b.id === id)
    const target = idx + dir
    if (target < 0 || target >= blocks.length) return
    ;[blocks[idx], blocks[target]] = [blocks[target], blocks[idx]]
    updateScreen({ ...screen, blocks })
  }

  function updateBlock(id: string, patch: Partial<Block>) {
    updateScreen({ ...screen, blocks: screen.blocks.map(b => b.id === id ? { ...b, ...patch } : b) })
  }

  function addOption(blockId: string) {
    const b = screen.blocks.find(x => x.id === blockId)!
    updateBlock(blockId, { options: [...(b.options ?? []), { id: `opt_${Date.now()}`, title: 'New Option' }] })
  }

  function updateOption(blockId: string, optId: string, title: string) {
    const b = screen.blocks.find(x => x.id === blockId)!
    updateBlock(blockId, { options: (b.options ?? []).map(o => o.id === optId ? { ...o, title } : o) })
  }

  function removeOption(blockId: string, optId: string) {
    const b = screen.blocks.find(x => x.id === blockId)!
    updateBlock(blockId, { options: (b.options ?? []).filter(o => o.id !== optId) })
  }

  function deleteScreen(idx: number) {
    const ns = value.filter((_, i) => i !== idx)
    onChange(ns)
    setSelectedScreen(Math.max(0, idx - 1))
    setSelectedBlockId(null)
  }

  // ── Shared style tokens ────────────────────────────────────────────────────
  const fieldInput: React.CSSProperties = {
    width: '100%', background: 'var(--bg-active, #1a2730)',
    border: '1px solid var(--border, #2A3942)', borderRadius: 5,
    padding: '5px 8px', color: 'var(--text, #E9EDEF)',
    fontSize: 11, outline: 'none', boxSizing: 'border-box',
  }
  const fieldLabel: React.CSSProperties = {
    fontSize: 10, color: 'var(--text-muted, #8696A0)', marginBottom: 4,
  }
  const sectionHead: React.CSSProperties = {
    fontSize: 10, fontWeight: 700, color: 'var(--text-muted, #8696A0)',
    textTransform: 'uppercase', letterSpacing: 1, marginBottom: 8,
  }

  return (
    <div style={{ display: 'flex', height: '100%', minHeight: 0, overflow: 'hidden' }}>

      {/* ── LEFT — Screens + Palette ──────────────────────────────────────── */}
      <div style={{
        width: 176, borderRight: '1px solid var(--border, #2A3942)',
        display: 'flex', flexDirection: 'column', overflowY: 'auto', flexShrink: 0,
      }}>

        {/* Screen list */}
        <div style={{ padding: '10px 10px 8px', borderBottom: '1px solid var(--border, #2A3942)' }}>
          <div style={sectionHead}>Screens</div>
          {value.map((s, i) => (
            <div
              key={s.id}
              onClick={() => { setSelectedScreen(i); setSelectedBlockId(null) }}
              style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '5px 7px', borderRadius: 6, cursor: 'pointer', marginBottom: 2,
                background: selectedScreen === i ? 'var(--bg-active, #005C4B22)' : 'transparent',
                border: `1px solid ${selectedScreen === i ? '#00A884' : 'transparent'}`,
                transition: '.12s',
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 5, overflow: 'hidden', minWidth: 0 }}>
                {i === 0 && (
                  <span style={{ fontSize: 7, background: '#00A884', color: '#fff', padding: '1px 4px', borderRadius: 3, flexShrink: 0, fontWeight: 700 }}>
                    START
                  </span>
                )}
                <span style={{
                  fontSize: 11, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                  color: selectedScreen === i ? '#00A884' : 'var(--text, #E9EDEF)',
                }}>
                  {s.title}
                </span>
              </div>
              {i > 0 && (
                <button
                  onClick={e => { e.stopPropagation(); deleteScreen(i) }}
                  style={{ background: 'transparent', border: 'none', color: 'var(--text-muted, #8696A0)', cursor: 'pointer', fontSize: 13, padding: 0, lineHeight: 1, flexShrink: 0 }}
                >×</button>
              )}
            </div>
          ))}
          <button
            onClick={() => {
              const ns: Screen = { id: `screen_${Date.now()}`, title: `Screen ${value.length + 1}`, blocks: [] }
              onChange([...value, ns])
              setSelectedScreen(value.length)
              setSelectedBlockId(null)
            }}
            style={{
              width: '100%', marginTop: 5, background: 'transparent',
              border: '1px dashed var(--border, #374045)', borderRadius: 6,
              padding: '5px', color: 'var(--text-muted, #8696A0)',
              cursor: 'pointer', fontSize: 11,
            }}
          >+ Add Screen</button>
        </div>

        {/* Component palette */}
        <div style={{ padding: '10px 10px 8px', flex: 1 }}>
          <div style={sectionHead}>Add Component</div>
          {PALETTE.map(p => (
            <div
              key={p.type}
              onClick={() => addBlock(p.type)}
              title={p.desc}
              style={{
                display: 'flex', alignItems: 'center', gap: 7,
                padding: '5px 6px', borderRadius: 6, cursor: 'pointer', marginBottom: 2,
                border: '1px solid transparent', transition: '.12s',
              }}
              onMouseEnter={e => {
                e.currentTarget.style.background = 'var(--bg-active, #1a2730)'
                e.currentTarget.style.borderColor = 'var(--border, #2A3942)'
              }}
              onMouseLeave={e => {
                e.currentTarget.style.background = 'transparent'
                e.currentTarget.style.borderColor = 'transparent'
              }}
            >
              <div style={{
                width: 22, height: 22, borderRadius: 4, flexShrink: 0,
                background: TYPE_COLOR[p.type] + '1A',
                border: `1px solid ${TYPE_COLOR[p.type]}44`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 8, fontWeight: 700, color: TYPE_COLOR[p.type],
              }}>{p.icon}</div>
              <div>
                <div style={{ fontSize: 11, fontWeight: 500, color: 'var(--text, #E9EDEF)', lineHeight: 1.2 }}>{p.label}</div>
                <div style={{ fontSize: 9, color: 'var(--text-muted, #8696A0)' }}>{p.desc}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ── CENTER — Block list + property dock ───────────────────────────── */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0, overflow: 'hidden' }}>

        {/* Screen title bar */}
        <div style={{
          padding: '8px 12px', borderBottom: '1px solid var(--border, #2A3942)',
          display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0,
        }}>
          <input
            value={screen.title}
            onChange={e => updateScreen({ ...screen, title: e.target.value })}
            style={{
              flex: 1, background: 'transparent',
              border: '1px solid transparent', borderRadius: 5,
              padding: '3px 7px', color: 'var(--text, #E9EDEF)',
              fontSize: 12, fontWeight: 600, outline: 'none',
            }}
            onFocus={e => (e.target.style.borderColor = '#00A884')}
            onBlur={e => (e.target.style.borderColor = 'transparent')}
            placeholder="Screen title"
          />
          <span style={{ fontSize: 10, color: 'var(--text-muted, #8696A0)', whiteSpace: 'nowrap' }}>
            {screen.blocks.length} block{screen.blocks.length !== 1 ? 's' : ''}
          </span>
        </div>

        {/* Block list */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '10px 12px' }}>
          {screen.blocks.length === 0 && (
            <div style={{
              textAlign: 'center', padding: '36px 16px',
              color: 'var(--text-muted, #8696A0)', fontSize: 11,
              border: '1px dashed var(--border, #2A3942)', borderRadius: 8,
            }}>
              Click a component on the left to add it to this screen
            </div>
          )}

          {screen.blocks.map((b, idx) => {
            const pal = PALETTE.find(p => p.type === b.type)!
            const isSel = selectedBlockId === b.id
            return (
              <div
                key={b.id}
                onClick={() => setSelectedBlockId(isSel ? null : b.id)}
                style={{
                  display: 'flex', alignItems: 'center', gap: 8,
                  padding: '7px 9px', borderRadius: 7, cursor: 'pointer', marginBottom: 4,
                  background: isSel ? 'var(--bg-active, #005C4B1A)' : 'var(--bg-surface, #161b22)',
                  border: `1px solid ${isSel ? '#00A884' : 'var(--border, #2A3942)'}`,
                  transition: '.12s',
                }}
              >
                <div style={{
                  width: 26, height: 26, borderRadius: 5, flexShrink: 0,
                  background: TYPE_COLOR[b.type] + '1A',
                  border: `1px solid ${TYPE_COLOR[b.type]}44`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 8, fontWeight: 700, color: TYPE_COLOR[b.type],
                }}>{pal?.icon}</div>

                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 9, color: TYPE_COLOR[b.type], marginBottom: 1 }}>{pal?.label}</div>
                  <div style={{ fontSize: 11, color: 'var(--text, #E9EDEF)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {b.label || '(unlabeled)'}
                    {b.required && <span style={{ fontSize: 9, color: '#E74C3C', marginLeft: 4 }}>*</span>}
                  </div>
                </div>

                <div style={{ display: 'flex', gap: 2, flexShrink: 0 }} onClick={e => e.stopPropagation()}>
                  <button
                    onClick={() => moveBlock(b.id, -1)} disabled={idx === 0}
                    style={{ background: 'transparent', border: 'none', color: 'var(--text-muted, #8696A0)', cursor: idx === 0 ? 'not-allowed' : 'pointer', fontSize: 11, padding: '2px 3px', opacity: idx === 0 ? 0.3 : 0.7 }}
                  >↑</button>
                  <button
                    onClick={() => moveBlock(b.id, 1)} disabled={idx === screen.blocks.length - 1}
                    style={{ background: 'transparent', border: 'none', color: 'var(--text-muted, #8696A0)', cursor: idx === screen.blocks.length - 1 ? 'not-allowed' : 'pointer', fontSize: 11, padding: '2px 3px', opacity: idx === screen.blocks.length - 1 ? 0.3 : 0.7 }}
                  >↓</button>
                  <button
                    onClick={() => removeBlock(b.id)}
                    style={{ background: 'transparent', border: 'none', color: 'var(--text-muted, #8696A0)', cursor: 'pointer', fontSize: 14, padding: '2px 3px' }}
                  >×</button>
                </div>
              </div>
            )
          })}
        </div>

        {/* Property editor dock — appears when a block is selected */}
        {selectedBlock && (
          <div style={{
            borderTop: '1px solid var(--border, #2A3942)',
            padding: '12px 14px',
            background: 'var(--bg-surface, #0d1117)',
            flexShrink: 0, maxHeight: 240, overflowY: 'auto',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
              <div style={sectionHead as any}>
                Edit · {PALETTE.find(p => p.type === selectedBlock.type)?.label}
              </div>
              <button
                onClick={() => setSelectedBlockId(null)}
                style={{ background: 'transparent', border: 'none', color: 'var(--text-muted, #8696A0)', cursor: 'pointer', fontSize: 14, padding: 0 }}
              >×</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
              {/* Label / content */}
              <div>
                <div style={fieldLabel}>
                  {selectedBlock.type === 'heading' || selectedBlock.type === 'text' ? 'Text Content' : 'Label'}
                </div>
                <input
                  value={selectedBlock.label ?? ''}
                  onChange={e => updateBlock(selectedBlock.id, { label: e.target.value })}
                  style={fieldInput}
                  placeholder="Enter label"
                />
              </div>

              {selectedBlock.type === 'button' && (
  <div style={{ marginTop: 10 }}>
    <div style={fieldLabel}>Button Action</div>

    <select
      value={selectedBlock.action ?? 'submit'}
      onChange={e =>
        updateBlock(selectedBlock.id, {
          action: e.target.value as 'next' | 'submit'
        })
      }
      style={fieldInput}
    >
      <option value="submit">Submit Flow</option>
      <option value="next">Go To Next Screen</option>
    </select>

    {(selectedBlock.action ?? 'submit') === 'next' && (
      <>
        <div style={{ ...fieldLabel, marginTop: 8 }}>
          Target Screen
        </div>

        <select
          value={selectedBlock.targetScreen ?? ''}
          onChange={e =>
            updateBlock(selectedBlock.id, {
              targetScreen: e.target.value
            })
          }
          style={fieldInput}
        >
          <option value="">Select Screen</option>

          {value.map((s) => (
            <option key={s.id} value={s.id}>
              {s.title}
            </option>
          ))}
        </select>
      </>
    )}
  </div>
)}

              {/* Placeholder */}
              {['input', 'email', 'phone'].includes(selectedBlock.type) && (
                <div>
                  <div style={fieldLabel}>Placeholder</div>
                  <input
                    value={selectedBlock.placeholder ?? ''}
                    onChange={e => updateBlock(selectedBlock.id, { placeholder: e.target.value })}
                    style={fieldInput}
                    placeholder="Helper text"
                  />
                </div>
              )}

              {/* Required */}
              {!['heading', 'text', 'button'].includes(selectedBlock.type) && (
                <div style={{ display: 'flex', alignItems: 'center', gap: 7, paddingTop: 18 }}>
                  <input
                    type="checkbox"
                    id={`req-${selectedBlock.id}`}
                    checked={selectedBlock.required ?? false}
                    onChange={e => updateBlock(selectedBlock.id, { required: e.target.checked })}
                    style={{ accentColor: '#00A884', cursor: 'pointer', width: 13, height: 13 }}
                  />
                  <label htmlFor={`req-${selectedBlock.id}`} style={{ ...fieldLabel, cursor: 'pointer', marginBottom: 0, userSelect: 'none' }}>
                    Required field
                  </label>
                </div>
              )}
            </div>

            {/* Dropdown options editor */}
            {selectedBlock.type === 'dropdown' && (
              <div style={{ marginTop: 10 }}>
                <div style={{ ...fieldLabel, marginBottom: 6 }}>Options</div>
                {(selectedBlock.options ?? []).map((o, oi) => (
                  <div key={o.id} style={{ display: 'flex', gap: 6, marginBottom: 5, alignItems: 'center' }}>
                    <span style={{ fontSize: 10, color: 'var(--text-muted, #8696A0)', width: 16, textAlign: 'right', flexShrink: 0 }}>{oi + 1}.</span>
                    <input
                      value={o.title}
                      onChange={e => updateOption(selectedBlock.id, o.id, e.target.value)}
                      style={{ ...fieldInput, padding: '4px 7px' }}
                      placeholder={`Option ${oi + 1}`}
                    />
                    <button
                      onClick={() => removeOption(selectedBlock.id, o.id)}
                      style={{ background: 'transparent', border: 'none', color: 'var(--text-muted, #8696A0)', cursor: 'pointer', fontSize: 14, padding: '0 4px', flexShrink: 0 }}
                    >×</button>
                  </div>
                ))}
                <button
                  onClick={() => addOption(selectedBlock.id)}
                  style={{
                    background: 'transparent', border: '1px dashed var(--border, #374045)',
                    borderRadius: 5, padding: '3px 10px', color: 'var(--text-muted, #8696A0)',
                    cursor: 'pointer', fontSize: 10, marginTop: 2,
                  }}
                >+ Add Option</button>
              </div>
            )}

            {/* Button → next screen selector */}
            {selectedBlock.type === 'button' && value.length > 1 && (
              <div style={{ marginTop: 10 }}>
                <div style={fieldLabel}>Navigate to Screen</div>
                <select
                  value={screen.nextScreen ?? ''}
                  onChange={e => updateScreen({ ...screen, nextScreen: e.target.value || undefined })}
                  style={{ ...fieldInput, cursor: 'pointer' } as any}
                >
                  <option value="">— Complete Flow —</option>
                  {value.filter((_, i) => i !== selectedScreen).map(s => (
                    <option key={s.id} value={s.id}>{s.title}</option>
                  ))}
                </select>
              </div>
            )}
          </div>
        )}
      </div>

      {/* ── RIGHT — Phone Preview ─────────────────────────────────────────── */}
      <div style={{
        width: 224, borderLeft: '1px solid var(--border, #2A3942)',
        display: 'flex', flexDirection: 'column', overflowY: 'auto', flexShrink: 0,
      }}>
        <div style={{ padding: '10px 10px 6px', borderBottom: '1px solid var(--border, #2A3942)', ...sectionHead as any }}>
          Preview
        </div>
        <div style={{ flex: 1, overflowY: 'auto' }}>
          <PhonePreview screen={screen} />
        </div>
      </div>
    </div>
  )
}

/**
 * src/components/inbox/CallModal.tsx
 *
 * Full-screen call overlay that handles all states:
 *   idle → permission_required → requesting_permission
 *   → connecting → ringing → connected → ending → error
 *
 * Used by ChatWindow when the call icon button is clicked.
 * Props:
 *   conversationId  — active conversation
 *   contactName     — display name for the header
 *   contactPhone    — E.164 phone shown under name
 *   onClose         — callback when modal should be closed
 */

'use client'

import { useEffect } from 'react'
import { useWhatsAppCall, CallState } from '@/hooks/useWhatsAppCall'

interface CallModalProps {
  conversationId: string
  contactName:    string
  contactPhone?:  string
  onClose:        () => void
}

// ── Duration formatter ─────────────────────────────────────────────────────────
function fmtDuration(s: number): string {
  const h = Math.floor(s / 3600)
  const m = Math.floor((s % 3600) / 60)
  const sec = s % 60
  if (h > 0) return `${h}:${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`
  return `${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`
}

// ── State label ────────────────────────────────────────────────────────────────
function stateLabel(state: CallState): string {
  switch (state) {
    case 'checking':              return 'Checking…'
    case 'permission_required':   return 'Permission required'
    case 'requesting_permission': return 'Sending request…'
    case 'connecting':            return 'Connecting…'
    case 'ringing':               return 'Ringing…'
    case 'connected':             return 'Connected'
    case 'ending':                return 'Ending call…'
    case 'error':                 return 'Call failed'
    default:                      return ''
  }
}

// ── Avatar ─────────────────────────────────────────────────────────────────────
function Avatar({ name, pulse }: { name: string; pulse?: boolean }) {
  const initials = name
    .split(' ')
    .slice(0, 2)
    .map(w => w[0]?.toUpperCase() ?? '')
    .join('')

  return (
    <div style={{ position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      {pulse && (
        <div style={{
          position:     'absolute',
          width:         120,
          height:        120,
          borderRadius: '50%',
          background:   'rgba(255,255,255,0.15)',
          animation:    'wa-call-pulse 1.8s ease-in-out infinite',
        }} />
      )}
      {pulse && (
        <div style={{
          position:      'absolute',
          width:          100,
          height:         100,
          borderRadius:  '50%',
          background:    'rgba(255,255,255,0.12)',
          animation:     'wa-call-pulse 1.8s ease-in-out 0.4s infinite',
        }} />
      )}
      <div style={{
        width:          80,
        height:         80,
        borderRadius:  '50%',
        background:    'rgba(255,255,255,0.25)',
        display:        'flex',
        alignItems:     'center',
        justifyContent: 'center',
        fontSize:       28,
        fontWeight:     700,
        color:          '#fff',
        letterSpacing: '0.5px',
        position:       'relative',
        zIndex:         1,
        border:         '2px solid rgba(255,255,255,0.4)',
      }}>
        {initials || '?'}
      </div>
    </div>
  )
}

// ── Circular icon button ───────────────────────────────────────────────────────
function CircleBtn({
  onClick, disabled = false, danger = false, size = 56, children, label,
}: {
  onClick: () => void
  disabled?: boolean
  danger?: boolean
  size?: number
  children: React.ReactNode
  label: string
}) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      aria-label={label}
      title={label}
      style={{
        width:           size,
        height:          size,
        borderRadius:    '50%',
        border:          'none',
        background:      danger ? '#ef4444' : 'rgba(255,255,255,0.2)',
        color:           '#fff',
        display:         'flex',
        alignItems:      'center',
        justifyContent:  'center',
        cursor:          disabled ? 'not-allowed' : 'pointer',
        opacity:         disabled ? 0.5 : 1,
        transition:      'background 0.15s, transform 0.1s',
        backdropFilter:  'blur(4px)',
        flexShrink:      0,
      }}
      onMouseEnter={e => {
        if (!disabled) (e.currentTarget as HTMLButtonElement).style.background =
          danger ? '#dc2626' : 'rgba(255,255,255,0.3)'
      }}
      onMouseLeave={e => {
        if (!disabled) (e.currentTarget as HTMLButtonElement).style.background =
          danger ? '#ef4444' : 'rgba(255,255,255,0.2)'
      }}
    >
      {children}
    </button>
  )
}

// ── Icons (inline SVG — no extra deps) ────────────────────────────────────────
const MicIcon = ({ muted }: { muted: boolean }) => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    {muted ? (
      <>
        <line x1="1" y1="1" x2="23" y2="23" />
        <path d="M9 9v3a3 3 0 0 0 5.12 2.12M15 9.34V4a3 3 0 0 0-5.94-.6" />
        <path d="M17 16.95A7 7 0 0 1 5 12v-2m14 0v2a7 7 0 0 1-.11 1.23" />
        <line x1="12" y1="19" x2="12" y2="23" />
        <line x1="8" y1="23" x2="16" y2="23" />
      </>
    ) : (
      <>
        <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
        <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
        <line x1="12" y1="19" x2="12" y2="23" />
        <line x1="8" y1="23" x2="16" y2="23" />
      </>
    )}
  </svg>
)

const PhoneOffIcon = () => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M10.68 13.31a16 16 0 0 0 3.41 2.6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7 2 2 0 0 1 1.72 2v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A2 2 0 0 1 10.68 13.31z" />
    <line x1="1" y1="1" x2="23" y2="23" />
  </svg>
)

const PhoneIcon = () => (
  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 15a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 4.18L6.6 4a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.91 11.56a16 16 0 0 0 6.15 6.15l.54-.54a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 21.3 15.6l-.38 1.32z" />
  </svg>
)

const AlertIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="12" r="10" />
    <line x1="12" y1="8" x2="12" y2="12" />
    <line x1="12" y1="16" x2="12.01" y2="16" />
  </svg>
)

// ── Main Component ─────────────────────────────────────────────────────────────
export default function CallModal({ conversationId, contactName, contactPhone, onClose }: CallModalProps) {
const {
    callState, callId, permission, duration, isMuted, error,
    isRecording, recordingUploading, recordingUrl,
    checkPermission, requestPermission, startCall, endCall, toggleMute, reset,
    startRecording, stopRecording,
  } = useWhatsAppCall(conversationId)

  // Check permission on open
  useEffect(() => {
    checkPermission()
  }, [checkPermission])

  // ESC to close (only when not in an active call)
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && callState !== 'connected' && callState !== 'connecting' && callState !== 'ringing') {
        handleClose()
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [callState])

  function handleClose() {
    if (callState === 'connected' || callState === 'ringing' || callState === 'connecting') {
      endCall().then(onClose)
    } else {
      reset()
      onClose()
    }
  }

  const isPulse  = callState === 'ringing' || callState === 'connecting'
  const isActive = callState === 'connected'

  return (
    <>
      {/* Keyframe injection */}
      <style>{`
        @keyframes wa-call-pulse {
          0%   { transform: scale(1);   opacity: 0.6; }
          50%  { transform: scale(1.35);opacity: 0; }
          100% { transform: scale(1);   opacity: 0; }
        }
        @keyframes wa-call-fadein {
          from { opacity: 0; transform: translateY(12px) scale(0.97); }
          to   { opacity: 1; transform: translateY(0)    scale(1); }
        }
      `}</style>

      {/* Backdrop */}
      <div
        onClick={e => { if (e.target === e.currentTarget) handleClose() }}
        style={{
          position:       'fixed',
          inset:           0,
          background:     'rgba(0,0,0,0.65)',
          backdropFilter: 'blur(6px)',
          display:        'flex',
          alignItems:     'center',
          justifyContent: 'center',
          zIndex:          9999,
        }}
      >
        {/* Card */}
        <div style={{
          width:          340,
          borderRadius:   24,
          background:     isActive
            ? 'linear-gradient(145deg, #075e54 0%, #128c7e 100%)'
            : callState === 'error'
              ? 'linear-gradient(145deg, #7f1d1d 0%, #b91c1c 100%)'
              : 'linear-gradient(145deg, #1a2a2a 0%, #0d1f1c 100%)',
          padding:        '36px 28px 28px',
          display:        'flex',
          flexDirection:  'column',
          alignItems:     'center',
          gap:             20,
          boxShadow:      '0 32px 80px rgba(0,0,0,0.6)',
          animation:      'wa-call-fadein 0.25s ease',
          position:       'relative',
        }}>
          {/* Close button (top-right) */}
          {(callState === 'idle' || callState === 'permission_required' || callState === 'error' || callState === 'checking') && (
            <button
              onClick={handleClose}
              style={{
                position:   'absolute',
                top:         14,
                right:       16,
                background: 'transparent',
                border:     'none',
                color:      'rgba(255,255,255,0.55)',
                cursor:     'pointer',
                fontSize:    20,
                lineHeight: 1,
                padding:     4,
              }}
              aria-label="Close"
            >✕</button>
          )}

          {/* Avatar */}
          <Avatar name={contactName} pulse={isPulse} />

          {/* Contact info */}
          <div style={{ textAlign: 'center', color: '#fff' }}>
            <div style={{ fontSize: 20, fontWeight: 700, letterSpacing: '-0.3px' }}>{contactName}</div>
            {contactPhone && (
              <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.6)', marginTop: 2 }}>
                {contactPhone}
              </div>
            )}
            <div style={{
              fontSize:    13,
              color:       isActive ? '#86efac' : 'rgba(255,255,255,0.65)',
              marginTop:   6,
              fontVariant: 'tabular-nums',
            }}>
              {isActive ? fmtDuration(duration) : stateLabel(callState)}
            </div>
          </div>

          {/* ── Error state ── */}
          {callState === 'error' && (
            <div style={{
              background:   'rgba(255,255,255,0.1)',
              borderRadius:  12,
              padding:      '12px 16px',
              color:        '#fca5a5',
              fontSize:      13,
              textAlign:    'center',
              display:      'flex',
              gap:           8,
              alignItems:   'center',
            }}>
              <AlertIcon />
              {error ?? 'An error occurred'}
            </div>
          )}

          {/* ── Permission required state ── */}
          {callState === 'permission_required' && (
            <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div style={{
                background:   'rgba(255,255,255,0.08)',
                borderRadius:  12,
                padding:      '12px 14px',
                color:        'rgba(255,255,255,0.8)',
                fontSize:      13,
                lineHeight:    1.5,
                textAlign:    'center',
              }}>
                {permission?.status === 'pending'
                  ? '⏳ Permission request sent. The contact will see a prompt in their WhatsApp to allow calls.'
                  : 'You need permission to call this contact. Send them a request and they can approve it in WhatsApp.'}
              </div>

              {permission?.can_request && permission?.status !== 'pending' && (
                <button
                  onClick={requestPermission}
                  style={{
                    background:   '#25d366',
                    border:       'none',
                    borderRadius:  12,
                    color:        '#fff',
                    fontSize:      14,
                    fontWeight:    600,
                    padding:      '13px 20px',
                    cursor:       'pointer',
                    display:      'flex',
                    alignItems:   'center',
                    justifyContent: 'center',
                    gap:            8,
                  }}
                >
                  <PhoneIcon />
                  Send Permission Request
                </button>
              )}

              <button
                onClick={handleClose}
                style={{
                  background:   'rgba(255,255,255,0.1)',
                  border:       'none',
                  borderRadius:  12,
                  color:        'rgba(255,255,255,0.7)',
                  fontSize:      13,
                  padding:      '10px 20px',
                  cursor:       'pointer',
                }}
              >
                Cancel
              </button>
            </div>
          )}

          {/* ── Requesting permission loading state ── */}
          {callState === 'requesting_permission' && (
            <div style={{
              color:      'rgba(255,255,255,0.7)',
              fontSize:    14,
              textAlign:  'center',
            }}>
              Sending request to {contactName}…
            </div>
          )}

          {/* ── Idle (can call) ── */}
          {callState === 'idle' && (
            <button
              onClick={startCall}
              style={{
                background:    '#25d366',
                border:        'none',
                borderRadius:   16,
                color:         '#fff',
                fontSize:       15,
                fontWeight:     600,
                padding:       '14px 28px',
                cursor:        'pointer',
                display:       'flex',
                alignItems:    'center',
                gap:            8,
                transition:    'background 0.15s',
              }}
              onMouseEnter={e => (e.currentTarget.style.background = '#1db954')}
              onMouseLeave={e => (e.currentTarget.style.background = '#25d366')}
            >
              <PhoneIcon />
              Start Call
            </button>
          )}

          {/* ── Checking ── */}
          {callState === 'checking' && (
            <div style={{ color: 'rgba(255,255,255,0.6)', fontSize: 14 }}>
              Checking permissions…
            </div>
          )}

          {/* ── Connecting / Ringing / Connected call controls ── */}
          {(callState === 'connecting' || callState === 'ringing' || callState === 'connected' || callState === 'ending') && (
            <div style={{ display: 'flex', gap: 24, alignItems: 'center', marginTop: 4 }}>

              {/* Record */}
  <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}>
    <CircleBtn
      onClick={isRecording ? stopRecording : startRecording}
      disabled={callState !== 'connected'}
      danger={isRecording}
      label={isRecording ? 'Stop Recording' : 'Record'}
    >
      {isRecording ? (
        <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
          <rect x="6" y="6" width="12" height="12" rx="2" />
        </svg>
      ) : (
        <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
          <circle cx="12" cy="12" r="8" />
        </svg>
      )}
    </CircleBtn>
    <span style={{ color: 'rgba(255,255,255,0.55)', fontSize: 11 }}>
      {isRecording ? 'Stop' : 'Record'}
    </span>
  </div>

AND add recording status display after the controls section:
  {recordingUploading && (
    <div style={{ fontSize: 12, color: '#a78bfa', textAlign: 'center' }}>
      Uploading recording…
    </div>
  )}
  {recordingUrl && !recordingUploading && (
    <div style={{ fontSize: 12, color: '#86efac', textAlign: 'center' }}>
      ✓ Recording saved
    </div>
  )}

              {/* Mute */}
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}>
                <CircleBtn
                  onClick={toggleMute}
                  disabled={callState !== 'connected'}
                  label={isMuted ? 'Unmute' : 'Mute'}
                >
                  <MicIcon muted={isMuted} />
                </CircleBtn>
                <span style={{ color: 'rgba(255,255,255,0.55)', fontSize: 11 }}>
                  {isMuted ? 'Unmute' : 'Mute'}
                </span>
              </div>

              {/* End Call */}
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}>
                <CircleBtn
                  onClick={() => endCall().then(onClose)}
                  danger
                  size={64}
                  disabled={callState === 'ending'}
                  label="End call"
                >
                  <PhoneOffIcon />
                </CircleBtn>
                <span style={{ color: 'rgba(255,255,255,0.55)', fontSize: 11 }}>End</span>
              </div>
            </div>
          )}

          {/* Retry button on error */}
          {callState === 'error' && (
            <div style={{ display: 'flex', gap: 10, width: '100%' }}>
              <button
                onClick={() => { reset(); checkPermission() }}
                style={{
                  flex:         1,
                  background:   'rgba(255,255,255,0.1)',
                  border:       'none',
                  borderRadius:  12,
                  color:        '#fff',
                  fontSize:      14,
                  fontWeight:    500,
                  padding:      '12px',
                  cursor:       'pointer',
                }}
              >
                Retry
              </button>
              <button
                onClick={handleClose}
                style={{
                  flex:         1,
                  background:   'rgba(255,255,255,0.06)',
                  border:       'none',
                  borderRadius:  12,
                  color:        'rgba(255,255,255,0.6)',
                  fontSize:      14,
                  padding:      '12px',
                  cursor:       'pointer',
                }}
              >
                Close
              </button>
            </div>
          )}

          {/* WhatsApp branding dot */}
          <div style={{
            display:       'flex',
            alignItems:    'center',
            gap:            5,
            color:         'rgba(255,255,255,0.3)',
            fontSize:       11,
            marginTop:     -4,
          }}>
            <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor" opacity={0.6}>
              <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347z" />
              <path d="M12 0C5.373 0 0 5.373 0 12c0 2.12.552 4.11 1.518 5.837L.057 23.88l6.204-1.628A11.93 11.93 0 0 0 12 24c6.627 0 12-5.373 12-12S18.627 0 12 0zm0 21.818a9.818 9.818 0 0 1-5.032-1.383l-.36-.214-3.732.979 .997-3.648-.234-.374A9.818 9.818 0 1 1 12 21.818z" />
            </svg>
            WhatsApp Call
          </div>
        </div>
      </div>
    </>
  )
}

'use client'
import { useEffect, useRef, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useInboxStore, useActiveConversation } from '@/stores/useInboxStore'
import { formatMessageDate } from '@/lib/utils'
import MessageBubble from './MessageBubble'
import InputArea from './InputArea'
import type { Conversation, Message } from '@/types'
import CallModal from '@/components/inbox/CallModal'

const STATUS_CYCLE = ['open', 'pending', 'closed'] as const
const STATUS_LABEL = { open: 'Open', pending: 'Pending', closed: 'Closed' }

export default function ChatWindow() {
  const supabase = createClient()
  const {
    activeConversationId,
    messages,
    setMessages,
    addMessage,
    updateMessage,
    updateConversation,
  } = useInboxStore()
  const conversation = useActiveConversation()
  const platform = conversation?.platform ?? 'whatsapp'
  const isWA     = platform === 'whatsapp'

  const [activeTab,   setActiveTab]   = useState<'messages' | 'notes' | 'comments'>('messages')
  const [status,      setStatus]      = useState<'open' | 'pending' | 'closed'>('open')
  // Track which comment the agent is replying to in the Comments tab
  const [replyingTo, setReplyingTo]  = useState<{ id: string; body: string } | null>(null)

  // ── WhatsApp Call modal state ──────────────────────────────────────────────
  const [showCallModal, setShowCallModal] = useState(false)

  const bottomRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    setActiveTab('messages')
    setReplyingTo(null)
  }, [activeConversationId])

  const loadMessages = useCallback(async () => {
    if (!activeConversationId) return
    const { data, error } = await supabase
      .from('messages')
      .select('*, sender:profiles(id, full_name, avatar_url, role, email, workspace_id, is_online, created_at)')
      .eq('conversation_id', activeConversationId)
      .order('created_at', { ascending: true })
      .limit(200)
    if (error) { console.error('[ChatWindow] loadMessages error:', error.message); return }
    if (data) {
      // Issue (hide calls): filter out call-type messages — they show in /calls tab only
      setMessages((data as Message[]).filter(m => m.content_type !== 'call'))
    }

    // Mark conversation as read
    await supabase.from('conversations').update({ unread_count: 0 }).eq('id', activeConversationId)
    updateConversation(activeConversationId, { unread_count: 0 })

    // Send WA read receipts for last 5 unread inbound messages
    if (isWA && data) {
      const unread = data.filter(m => m.direction === 'inbound' && m.status !== 'read' && m.external_id)
      if (unread.length > 0) {
        unread.slice(-5).forEach(m => {
          fetch('/api/messages/mark-read', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ message_id: m.id, external_id: m.external_id }),
          }).catch(() => {})
        })
      }
    }
  }, [activeConversationId, isWA])

  useEffect(() => {
    loadMessages()
  }, [loadMessages])

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  // Realtime subscription
  useEffect(() => {
    if (!activeConversationId) return
    const channel = supabase
      .channel(`messages:${activeConversationId}`)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${activeConversationId}`,
      }, payload => {
  if (payload.eventType === 'INSERT') {
    const msg = payload.new as Message
    // Skip call-type messages — they live in the /calls tab only
    if (msg.content_type !== 'call') {
      addMessage(msg)
    }
  } else if (payload.eventType === 'UPDATE') {
          updateMessage((payload.new as Message).id, payload.new as Partial<Message>)
        }
      })
      .subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [activeConversationId])

  // Cycle conversation status
  async function cycleStatus() {
    if (!activeConversationId) return
    const idx = STATUS_CYCLE.indexOf(status)
    const next = STATUS_CYCLE[(idx + 1) % STATUS_CYCLE.length]
    setStatus(next)
    await supabase.from('conversations').update({ status: next }).eq('id', activeConversationId)
    updateConversation(activeConversationId, { status: next })
  }

  if (!conversation || !activeConversationId) {
    return (
      <div id="main-workspace" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 12, color: 'var(--text-muted)' }}>
        <i className="fa-brands fa-whatsapp" style={{ fontSize: 48, opacity: 0.12 }} />
        <p style={{ fontSize: 14 }}>Select a conversation to get started</p>
      </div>
    )
  }

  const contactName    = conversation.contact?.name || conversation.contact?.phone || conversation.contact?.instagram_username || 'Unknown'
  const contactPhone   = conversation.contact?.phone ?? undefined
  const platformIcon   = { whatsapp: 'fa-brands fa-whatsapp', instagram: 'fa-brands fa-instagram', facebook: 'fa-brands fa-facebook' }[platform]
  const platformCls    = { whatsapp: 'pp-wa', instagram: 'pp-ig', facebook: 'pp-fb' }[platform]
  const platformLabel  = { whatsapp: 'WhatsApp', instagram: 'Instagram', facebook: 'Facebook' }[platform]
  const badgeCls       = { whatsapp: 'pb-wa', instagram: 'pb-ig', facebook: 'pb-fb' }[platform]

  // Build date groups — filter messages by active tab
  const dateGroups: { date: string; msgs: Message[] }[] = []
  const displayMsgs = messages.filter(m => {
    if (activeTab === 'notes')    return m.is_note
    if (activeTab === 'comments') return m.content_type === 'comment'
    return !m.is_note && m.content_type !== 'comment'
  })
  for (const msg of displayMsgs) {
    const d    = formatMessageDate(msg.created_at)
    const last = dateGroups[dateGroups.length - 1]
    if (!last || last.date !== d) dateGroups.push({ date: d, msgs: [msg] })
    else last.msgs.push(msg)
  }

  const tabs: ('messages' | 'notes' | 'comments')[] = isWA ? ['messages', 'notes'] : ['messages', 'notes', 'comments']

  return (
    <div id="main-workspace">
      {/* ── Header ── */}
      <div className="chat-header">
        <div className="chat-contact">
          <div className="avatar-wrap">
            <div className="avatar"
              style={{ background: '#1a6b3a', width: 40, height: 40, fontSize: 14, fontWeight: 700, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff' }}>
              {contactName.slice(0, 2).toUpperCase()}
            </div>
            <div className={`platform-badge ${badgeCls}`}>
              <i className={platformIcon} style={{ fontSize: '8px' }} />
            </div>
          </div>
          <div className="chat-contact-info">
            <div className="name">{contactName}</div>
            <div className="sub">
              <span className={`platform-pill-sm ${platformCls}`}><i className={platformIcon} /> {platformLabel}</span>
              {conversation.status === 'open' && <span style={{ color: 'var(--accent)', fontSize: 11 }}>● Online</span>}
            </div>
          </div>
        </div>
        <div className="chat-header-actions">
          <div className={`status-pill ${status}`} onClick={cycleStatus}>
            <i className="fa-solid fa-circle" style={{ fontSize: '7px' }} />
            <span>{STATUS_LABEL[status]}</span>
          </div>

          {/* ── WhatsApp Call Button — only shown for WA conversations ── */}
          {isWA && (
            <button
              className="icon-btn"
              title="WhatsApp Voice Call"
onClick={() => setShowCallModal(true)}
              style={{
                position:   'relative',
                color:       'var(--text-muted)',
              }}
            >
              {/* Inline SVG phone icon — no extra dep needed */}
              <svg
                width="15"
                height="15"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                style={{ display: 'block' }}
              >
                <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 15a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 4.18L6.6 4a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.91 11.56a16 16 0 0 0 6.15 6.15l.54-.54a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 21.3 15.6l-.38 1.32z" />
              </svg>
            </button>
          )}

          <button className="icon-btn" title="Search"><i className="fa-solid fa-magnifying-glass" /></button>
          <button className="icon-btn" title="More"><i className="fa-solid fa-ellipsis-vertical" /></button>
        </div>
      </div>

      {/* ── Tabs ── */}
      <div className="workspace-tabs">
        {tabs.map(tab => (
          <div
            key={tab}
            className={`ws-tab ${activeTab === tab ? 'active' : ''}`}
            onClick={() => { setActiveTab(tab); setReplyingTo(null) }}
          >
            {tab === 'messages' && <><i className="fa-solid fa-message" /> Messages</>}
            {tab === 'notes' && (
              <><i className="fa-solid fa-note-sticky" /> Notes
                {messages.filter(m => m.is_note).length > 0 && (
                  <span className="tab-badge">{messages.filter(m => m.is_note).length}</span>
                )}
              </>
            )}
            {tab === 'comments' && (
              <>
                <i className={platformIcon} style={{ color: platform === 'instagram' ? '#e1306c' : '#1877f2' }} /> Comments
                {messages.filter(m => m.content_type === 'comment').length > 0 && (
                  <span className="tab-badge">{messages.filter(m => m.content_type === 'comment').length}</span>
                )}
              </>
            )}
          </div>
        ))}
      </div>

      {/* ── Messages area ── */}
      <div className="workspace-content">
        {activeTab === 'notes' && (
          <div className="note-intro"><i className="fa-solid fa-lock" /> Internal notes — never sent to customer.</div>
        )}
        {activeTab === 'comments' && (
          <div className="note-intro" style={{ borderColor: 'rgba(24,119,242,0.2)', color: 'var(--text-secondary)' }}>
            <i className={platformIcon} style={{ color: platform === 'instagram' ? '#e1306c' : '#1877f2' }} />
            {' '}Public comments on your {platform === 'instagram' ? 'Instagram' : 'Facebook'} posts. Click Reply on any comment below.
          </div>
        )}

        {dateGroups.length === 0 ? (
          <div className="empty-state">
            <i className="fa-brands fa-whatsapp" style={{ fontSize: 48, opacity: 0.15 }} />
            <p style={{ fontSize: 13, color: 'var(--text-muted)' }}>
              {activeTab === 'messages' ? 'No messages yet.'
                : activeTab === 'notes' ? 'No notes yet.'
                : 'No comments yet.'}
            </p>
          </div>
        ) : (
          dateGroups.map(group => (
            <div key={group.date}>
              <div className="date-divider"><span>{group.date}</span></div>
              {group.msgs.map((msg, i) => {
                const prev    = group.msgs[i - 1]
                const next    = group.msgs[i + 1]
                const isFirst = !prev || prev.direction !== msg.direction ||
                  new Date(msg.created_at).getTime() - new Date(prev.created_at).getTime() > 5 * 60000
                const isLast  = !next || next.direction !== msg.direction ||
                  new Date(next.created_at).getTime() - new Date(msg.created_at).getTime() > 5 * 60000
                return (
                  <MessageBubble
                    key={msg.id}
                    message={msg}
                    isFirstInGroup={isFirst}
                    isLastInGroup={isLast}
                    // CRITICAL: pass full message list so quoted replies can look up the original
                    allMessages={displayMsgs}
                    onSetReply={
                      activeTab === 'comments'
                        ? (id, body) => setReplyingTo({ id, body })
                        : undefined
                    }
                  />
                )
              })}
            </div>
          ))
        )}
        <div ref={bottomRef} />
      </div>

      {/* ── Input area — switches by tab ── */}
      {activeTab === 'messages' && <InputArea onMessageSent={loadMessages} />}
      {activeTab === 'notes'    && <NoteInput conversationId={activeConversationId!} onSaved={loadMessages} />}
      {activeTab === 'comments' && (
        <CommentReplyInput
          conversation={conversation}
          replyingTo={replyingTo}
          onClearReply={() => setReplyingTo(null)}
          onSent={() => { loadMessages(); setReplyingTo(null) }}
        />
      )}

  {/* ── WhatsApp Call Modal (portal-style overlay) ── */}
  {showCallModal && isWA && (
    <CallModal
      conversationId={activeConversationId!}
      contactName={contactName}
      contactPhone={contactPhone}
      onClose={() => setShowCallModal(false)}
    />
  )}    </div>
  )
}

/* -------------------------------------------------------------------------- */
/* Internal Note Input                                                        */
/* -------------------------------------------------------------------------- */

function NoteInput({ conversationId, onSaved }: { conversationId: string; onSaved: () => void }) {
  const [text, setText] = useState('')
  const supabase = createClient()

  async function save() {
    if (!text.trim()) return
    const { data: { session } } = await supabase.auth.getSession()
    if (!session) return
    const { data: p } = await supabase.from('profiles').select('workspace_id').eq('id', session.user.id).single()
    if (!p) return
    await supabase.from('messages').insert({
      conversation_id: conversationId,
      workspace_id:    p.workspace_id,
      direction:       'outbound',
      content_type:    'text',
      body:            text.trim(),
      is_note:         true,
      status:          'sent',
      sender_id:       session.user.id,
    })
    setText('')
    onSaved()
  }

  return (
    <div className="notes-input-area">
      <div className="input-row">
        <textarea
          className="input-box"
          placeholder="Add an internal note… (Enter to save)"
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); save() } }}
          rows={1}
          style={{ borderColor: 'rgba(245,158,11,0.4)' }}
        />
        <button className="send-btn" style={{ background: 'var(--accent3)' }} onClick={save}>
          <i className="fa-solid fa-plus" />
        </button>
      </div>
    </div>
  )
}

/* -------------------------------------------------------------------------- */
/* Comment Reply Input                                                        */
/* -------------------------------------------------------------------------- */

interface CommentReplyInputProps {
  conversation: Conversation
  replyingTo: { id: string; body: string } | null
  onClearReply: () => void
  onSent: () => void
}

function CommentReplyInput({ conversation, replyingTo, onClearReply, onSent }: CommentReplyInputProps) {
  const [text,    setText]    = useState('')
  const [sending, setSending] = useState(false)
  const [error,   setError]   = useState('')
  const textRef = useRef<HTMLTextAreaElement>(null)

  async function send() {
    if (!text.trim() || sending) return
    if (!replyingTo) {
      setError('Select a comment to reply to by clicking Reply below it.')
      return
    }
    setError('')
    setSending(true)
    try {
      const res  = await fetch('/api/messages/send', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({
          conversation_id: conversation.id,
          type:            'comment_reply',
          comment_id:      replyingTo.id,
          body:            text.trim(),
        }),
      })
      const json = await res.json()
      if (!res.ok) setError(json.error || 'Failed to send reply')
      else { setText(''); onSent() }
    } catch (err: any) {
      setError(err.message || 'Network error')
    } finally {
      setSending(false)
    }
  }

  const platformIcon  = { facebook: 'fa-brands fa-facebook', instagram: 'fa-brands fa-instagram', whatsapp: 'fa-brands fa-whatsapp' }[conversation.platform]
  const platformColor = conversation.platform === 'instagram' ? '#e1306c' : '#1877f2'

  return (
    <div className="notes-input-area" style={{ borderTop: '1px solid var(--border)' }}>
      {/* Reply target indicator */}
      {replyingTo ? (
        <div style={{ display: 'flex', alignItems: 'flex-start', gap: 8, padding: '6px 12px', background: 'var(--bg-surface)', borderBottom: '1px solid var(--border)', fontSize: 12 }}>
          <i className="fa-solid fa-reply" style={{ color: platformColor, marginTop: 2, flexShrink: 0 }} />
          <span style={{ flex: 1, color: 'var(--text-secondary)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            Replying to: <em>{replyingTo.body.slice(0, 60)}{replyingTo.body.length > 60 ? '…' : ''}</em>
          </span>
          <button onClick={onClearReply} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', padding: 0, flexShrink: 0 }}>
            <i className="fa-solid fa-xmark" />
          </button>
        </div>
      ) : (
        <div style={{ padding: '5px 12px', fontSize: 11, color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: 5 }}>
          <i className={platformIcon} style={{ color: platformColor }} />
          Click <strong>Reply</strong> on a comment above to respond publicly
        </div>
      )}

      {error && (
        <div style={{ padding: '4px 12px', fontSize: 11, color: '#e84040' }}>
          <i className="fa-solid fa-circle-exclamation" style={{ marginRight: 4 }} />{error}
        </div>
      )}

      <div className="input-row">
        <textarea
          ref={textRef}
          className="input-box"
          placeholder={replyingTo ? 'Write a public reply…' : 'Select a comment to reply to first…'}
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send() } }}
          rows={1}
          disabled={sending || !replyingTo}
          style={{ borderColor: replyingTo ? `${platformColor}44` : undefined, opacity: replyingTo ? 1 : 0.6 }}
        />
        <button
          className="send-btn"
          style={{ background: replyingTo ? platformColor : 'var(--bg-surface)', opacity: (sending || !text.trim() || !replyingTo) ? 0.5 : 1 }}
          onClick={send}
          disabled={sending || !text.trim() || !replyingTo}
        >
          {sending
            ? <i className="fa-solid fa-spinner fa-spin" />
            : <i className="fa-solid fa-paper-plane" />}
        </button>
      </div>
    </div>
  )
}
